import minimist = require('minimist');
import chalk = require('chalk');
import Rulify from './Rulify';

export default function cli() {

    const args:any = minimist(process.argv.slice(2), {
        alias: {
            "v": "verbose",
            "i": "input",
            "o": "output",
            "f": "force"
        },
        boolean: ['update', 'verbose', 'force', 'launchRules'],
        string: ['output', 'input']
    });

    let result:any;

    if (args.launchRules) {
        result = Rulify.compileLaunchRules(
            args.input,
            args.verbose,
            args.force
        );
    } else {
        result = Rulify.exec(
            args.input,
            args.output,
            args.verbose
        );
    }

    result.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        process.exit(0);
    });

    result.on('fileError', (err) => {
        console.log(chalk.red(err));
    });

    result.on('compileError', (filename, err) => {
        console.error(chalk.underline(filename));
        console.error(chalk.red(err));
    });

    result.on('log', (message) => {
        console.log(chalk.green(message));
    });
}
