import JiboDev from '../JiboDev';
import Rulify from '../../rules/Rulify';
import chalk = require('chalk');

export default function(gulp, dev:JiboDev) {
    gulp.task('rules', ['clean'], function(done){
        const result = Rulify.exec(
            dev.config.rulesSrc,
            dev.config.rules,
            dev.args.verbose
        );
        result.on('end', (err) => {
            done();
        });
        result.on('fileError', (err) => {
            console.log(chalk.red(err));
        });
        result.on('compileError', (filename, err) => {
            console.error(chalk.underline(filename));
            console.error(chalk.red(err));
        });
        result.on('log', (message) => {
            console.log(chalk.green(message));
        });
    });
}
