import findRoot = require('find-root');
import path = require('path');
import fs = require('fs');
import cli from './cli';
import mkdirp = require('mkdirp');
import glob = require('glob');
import {EventEmitter} from 'events';
import normalize = require('normalize-path');
import crypto = require('crypto');
import os = require('os');
import moment = require('moment');

let handleId = 1;

/**
 * Callback for asynchronous rule conversion.
 * @callback Rulify~Callback
 * @param {Error} error If conversion failed.
 * @param {String} output The output file path.
 */

 interface RulifyErrors {
     errorType:string;
     errorValue:string;
     err:any;
 }

/**
 * Convert a `.rule` file to a `.fst` file.
 * ```
 * import {Rulify} from 'jibo-dev';
 * const fstPath = Rulify.sync('/path/to/file.rule');
 * console.log("FST file saved to: ", fstPath);
 * ```
 * @class Rulify
 */
export default class Rulify {

    private static _nlu:any;

    /**
     * Synchronous version of rulify.
     * @method Rulify.sync
     * @param {String} src Either the contents of the rule or the path to the source (.rule or .fst)
     * @param {String} output Name of file to write, will default to src with `.fst` extension.
     * @return {String} The output file saved.
     */
    static sync(src, output) {
        let srcIsFst:boolean = /\.fst$/.test(src);
        const data = (/\.rule$/.test(src) || srcIsFst) ?
            fs.readFileSync(src, 'utf8') : src;
        output = output || Rulify.defaultOutput(src);
        if (srcIsFst) {
            // We are merely re-outputting the source .fst file, maybe to a new location
            fs.writeFileSync(output, data);
        } else {
            // compile .rule data
            fs.writeFileSync(output, Rulify.toBuffer(data));
        }
        return output;
    }

    /**
     * Asynchronous version of rulify.
     * @method Rulify.async
     * @param {String} src Either the contents of the rule or the path to the source (.rule or .fst)
     * @param {String} [output] Name of file to write, will default to src with `.fst` extension.
     * @param {Rulify~Callback} callback Called when the conversion completes.
     */
    static async(src, output, callback): void {

        if (typeof output === "function") {
            callback = output;
            output = null;
        }

        let srcIsFst:boolean = /\.fst$/.test(src);

        if (srcIsFst || /\.rule$/.test(src)) {
            output = output || Rulify.defaultOutput(src);
            fs.readFile(src, 'utf8', function(err, data) {
                if (err) {
                    return callback(err);
                }
                if (srcIsFst) {
                    // No need to compile .fst, just send straight out
                    fs.writeFile(output, data, function(e) {
                        callback(e, output);
                    });
                } else {
                    Rulify.fromString(data, output, callback);
                }
            });
        }
        else
        {
            Rulify.fromString(src, output, callback);
        }
    }

    /**
     * Execute the commandline interface
     * @method Rulify.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    /**
     * Get the reference the NLU parser.
     * @method Rulify.nlu
     * @return {NLU} The nlu parser.
     */
    static get nlu(): any {

        if (!Rulify._nlu) {

            let nlu;

            const parserPath = (process.versions as any).electron ? 'parser-electron' : 'parser-node';
            const root = path.join(findRoot(__dirname));
            const nodePath = path.join(root, parserPath, 'build','Release','jsjibonlu.node');
            const dataDirectory = path.join(root, parserPath, 'deps', 'data');

            try {
                nlu = require(nodePath);
                nlu.set_data_dir(dataDirectory);
            }
            catch (e) {
                console.error(e);
                nlu = undefined;
            }
            Rulify._nlu = nlu;
        }
        return Rulify._nlu;
    }

    /**
     * Get the reference the NLU parser.
     * @method Rulify.exec
     * @param {Array<String>} files List of files to load
     * @param {String} input Input directory
     * @param {String} output Output directory
     * @param {Boolean} [verbose=false] Extra logging
     * @return {EventEmitter} Emitter dispatches 'end', 'fileError', 'compileError', and 'log'
     */
    static exec(input:string, output:string, verbose?:boolean): EventEmitter {

        const result = new EventEmitter();

        process.nextTick(() => {

            const files:string[] = glob.sync(path.join(input, '**/*.rule'));

            if (!files.length) {
                result.emit('end', 'Must provide files to process');
                return;
            }

            let outFiles:string[] = [];
            let errors:RulifyErrors = this.processRulesFiles(files, outFiles, input, output, true);
            if (errors) {
                result.emit(errors.errorType, errors.errorValue, errors.err);
            } else {
                if (verbose) {
                    for (let i:number = 0; i < outFiles.length; i++) {
                        result.emit('log', 'Saved \'' + files[i] + '\' to \'' + outFiles[i] + '\'');
                    }
                }

                result.emit('end');
            }
        });
        return result;
    }

    /**
     * Compiles a skill's launch rules into a single .fst file. The launch rules are listed in
     * the "rulesToBuild" array of the skill's package.json. The name of the .fst file to output
     * to is found in "launchRule" (it should default to something if launchRule is not found or
     * is an array -- to do)
     *
     * @method Rulify.compileLaunchRules
     * @param {String} packagePath input directory, containing package.json
     * @param {Boolean} [verbose=false] Extra logging
     * @param {Boolean} [forceCompile=false] Force compile even if cache exists
     * @return {EventEmitter} Emitter dispatches 'end', 'fileError', 'compileError', and 'log'
     */
    static compileLaunchRules(packagePath:string, verbose?:boolean, forceCompile?:boolean): EventEmitter {
        packagePath = packagePath || process.cwd();
        packagePath = path.resolve(packagePath);

        const result = new EventEmitter();

        // Track how long compile takes
        let startTime = moment();
        let endTime, elapsedTime;

        // Check if compiled rules cache exists
        const cacheMapFile = path.join(os.tmpdir(), 'fstCache.json');
        const cacheFile = path.join(os.tmpdir(), 'fstCache');
        let cacheMap = {};
        // If metadata file doesn't exist or is empty, need to create it
        if (fs.existsSync(cacheMapFile) && fs.statSync(cacheMapFile).size) {
            // Also need to protect against corrupted metadata
            try {
                cacheMap = JSON.parse(fs.readFileSync(cacheMapFile, 'utf8'));
            } catch (err) {
                console.log("Bad rules cache metadata, recreating");
                fs.writeFileSync(cacheMapFile, "");
                cacheMap = {'digest': null};
            }
        } else {
            // if not, then create one
            fs.writeFileSync(cacheMapFile, "");
            cacheMap = {'digest': null};
        }

        // Derive package object from package.json
        let pkg;
        try {
            pkg = require(path.join(packagePath, 'package.json'));
        }
        catch(e) {
            result.emit('end', 'Couldn\'t process package.json');
            return result;
        }

        // Where should final file go?
        let outputPath:string = 'launchRule.fst'; // default name, unless another specified
        if (typeof pkg.jibo.launchRule === "string") {
            outputPath = pkg.jibo.launchRule;
        }
        outputPath = path.resolve(packagePath, outputPath);

        process.nextTick(() => {
            // Get set of paths to rules from package.json
            const rules:string[] = pkg.jibo.rulesToBuild;

            if (!rules.length) {
                result.emit('end', 'Must provide files to process');
                return;
            }

            let digestUnion = '';
            for (let rule of rules) {
                const uri = path.resolve(packagePath, rule);
                let hash = crypto.createHash('sha256');
                hash.update(fs.readFileSync(uri, 'utf8'));
                digestUnion += hash.digest('hex');
            }

            if (!forceCompile && (digestUnion === cacheMap['digest'] && fs.existsSync(cacheFile))) {
                console.log("\n----------------");
                console.log("Using cached launch rules FST");
                console.log("----------------\n");
                let cachedData = fs.readFileSync(cacheFile);
                fs.writeFileSync(outputPath, cachedData);
                endTime = moment();
                elapsedTime = moment.duration(endTime.diff(startTime));
            } else {
                console.warn("\n----------------");
                console.warn("Cached launch rules FST unavailable or outdated.");
                console.warn("It may take a minute or so to recompile");
                console.warn("----------------\n");
                cacheMap['digest'] = digestUnion;
                fs.writeFileSync(cacheMapFile, JSON.stringify(cacheMap));

                let outUris:string[] = [];
                let errors:RulifyErrors = this.processRulesFiles(rules, outUris, packagePath, packagePath, false);
                if (errors) {
                    result.emit(errors.errorType, errors.errorValue, errors.err);
                } else {
                    // We have successfully compiled each .rule file to a .fst file in memory

                    if (verbose) {
                        for (let i:number = 0; i < outUris.length; i++) {
                            result.emit('log', 'Saved \'' + rules[i] + '\' to \'' + outUris[i] + '\'');
                        }
                    }

                    let unionHandle = null;
                    try {
                        // Compile all the .fst files in memory into a master .fst file
                        unionHandle = Rulify.compileUnion(outUris);
                    } catch (err) {
                        result.emit('compileError', 'unionize error', err.message);
                    }

                    if (unionHandle) {
                        // Output master .fst file to disk
                        let fst = Rulify.nlu.read_fst_from_uri(unionHandle);
                        fst.save_fst(outputPath);
                        // Create cached fst file
                        let cachedData = fs.readFileSync(outputPath);
                        fs.writeFileSync(cacheFile, cachedData);
                        if (verbose) {
                            result.emit('log', 'Generated union file \'' + outputPath + '\'');
                        }
                    }

                    //endTime = Date.now();
                    //console.log("Cache copy took: " + new Date().setMilliseconds(endTime-startTime).toString());
                    endTime = moment();
                    elapsedTime = moment.duration(endTime.diff(startTime));
                }
            }

            if (elapsedTime.asSeconds() < 60) {
              console.log("Compile took: " + elapsedTime.asSeconds() + " seconds");
            }  else {
              console.log("Compile took: " + elapsedTime.asMinutes() + " minutes");
            }
            result.emit('end');

        });

        return result;
    }

    /**
     * Given a set of .rule files, compile each of them in memory into a .fst file.
     * When this is done, the method will return an array of URIs which contain either
     * the paths to the .fst files on disk or handles to their instances in memory.
     *
     * @param  {string[]}     files        Array of paths to rule files, which are relative
     * @param  {string[]}     outUris      Array that will receive set of outputted URIs
     * @param  {string}       inputFolder  Base input folder
     * @param  {string}       outputFolder Base output folder (relevant only when outputting
     *                                     .fst files to disk)
     * @param  {boolean}      outputToDisk If true, .fst files will be outputted to disk;
     *                                     otherwise they exist in memory, referred to by
     *                                     their handles.
     * @return {RulifyErrors}              error structure, if any errors. Otherwise, return
     *                                     null
     */
    private static processRulesFiles(files:string[], outUris:string[], inputFolder:string, outputFolder:string, outputToDisk:boolean):RulifyErrors {
        // Make directory in case
        mkdirp.sync(path.resolve(outputFolder));

        files.forEach(function(filename){
            // if the input file a .fst, not a .rule
            let isFstFile:boolean = (filename.indexOf('.fst') !== -1);

            if (outputToDisk) {
                const uri = path.resolve(filename);

                // Make sure the file is valid
                try {
                    fs.statSync(uri);
                }
                catch (e) {
                    return {
                        errorType : 'fileError',
                        errorValue : "File does not exist '" + filename + "'",
                        err : null
                    };
                }

                // If it's a .fst file, it would be redundant to compile it
                let outputName;

                // Rebase to the input folder
                // (It's fine if the input file is already a .fst)
                if (inputFolder) {
                    outputName = filename.replace(/\.rule$/, '.fst')
                        .replace(normalize(inputFolder) + '/', '');
                }
                else {
                    outputName = path.basename(filename).replace(/\.rule$/, '.fst');
                }
                const outputFile = path.resolve(outputFolder, outputName);
                const outputDir = path.dirname(outputFile);

                // Make the output directory
                mkdirp.sync(outputDir);

                // We compile the .rule file into a .fst file on disk
                try {
                    Rulify.sync(uri, outputFile);
                    outUris.push(outputFile);
                }
                catch (err) {
                    // Handle compile errors
                    return {
                        errorType : 'compileError',
                        errorValue : filename,
                        err : err
                    };
                }
            } else {
                let outUri:string = null;
                try {
                    let inFile:string = path.resolve(inputFolder, filename);
                    // We compile the .rule file into memory and hang onto the handle for later
                    outUri = `handle:${++handleId}`;
                    if (isFstFile) {
                        Rulify.nlu.load_fst_from_fst_file(inFile, outUri);
                    } else {
                        const data = fs.readFileSync(inFile, 'utf8');
                        Rulify.nlu.compile_fst_from_text(data, outUri);
                    }
                } catch (err) {
                    // Handle compile errors
                    return {
                        errorType : 'compileError',
                        errorValue : filename,
                        err : err
                    };
                }
                outUris.push(outUri);
            }
        });

        return null;
    }

    /**
     * Convert file to .fst
     * @method Rulify.defaultOutput
     * @private
     * @param {String} file Convert
     * @return {String} File .fst path
     */
    private static defaultOutput(file:string):string {
        return file.replace(/\.rule$/, '.fst');
    }

    /**
     * Write the buffer from data string
     * @function fromString
     * @private
     * @param {String} data contents of .rule file
     * @param {String} output Path to file to save
     * @param {Rulify~Callback} callback Calls when write completes.
     */
    private static fromString(data, output, callback) {
        try {
            const buffer = Rulify.toBuffer(data);
            fs.writeFile(output, buffer, function(err) {
                callback(err, output);
            });
        }
        catch(err) {
            callback(err, output);
        }
    }

    /**
     * Create a buffer from data
     * @function toBuffer
     * @private
     * @param {String} data Contents of .rule file
     */
    private static toBuffer(data) {
        try {
            const fst = Rulify.nlu.compile_fst_from_text(data, `handle:${++handleId}`);
            return fst.to_buffer();
        }
        catch(e) {
            let error = JSON.parse(e.message);
            let message = `${error.exception}\n`;
            message += `${error.info.msg}\n`;
            if(error.info.line) {
                message += `line: ${error.info.line} `;
                if(error.info.column) {
                    message += `column: ${error.info.column} `;
                }
            }
            throw new Error(message);
        }
    }

    /**
     * Give a set of uris to compiled .fst files (either the paths of the files on
     * disk or handles to their in-memory instances), compile a master .fst file.
     * @param  {string[]} uris Array of uris
     */
    private static compileUnion(uris:string[]) {
        try {
            let unionHandle:string = `handle:${++handleId}`;
            Rulify.nlu.union_fst(uris, unionHandle);
            return unionHandle;
        }
        catch(e) {
            let error = JSON.parse(e.message);
            let message = `${error.exception}\n`;
            message += `${error.info.msg}\n`;
            if(error.info.line) {
                message += `line: ${error.info.line} `;
                if(error.info.column) {
                    message += `column: ${error.info.column} `;
                }
            }
            throw new Error(message);
        }
    }
}
