import minimist = require('minimist');
import chalk = require('chalk');
import { AnimRefChecker } from './anim-ref-checker';

function usage() {
    console.log(`usage: node anim-ref-cheker.js [options]
  options:
    -s --check-skill /path/to/skill/folder (side effect: creates animdb-manifest.json in skill's top level directory)
    -m --check-manifest /path/to/animdb-manifest.json (can also be a URL that returns the **RAW** JSON text.)
    -a --use-animdb /path/to/animdb.json
    --no-manifest ; don't generate an animdb-manifest.json file
    --no-report ; don't generate a reference check report
    --verbose ; report on files that have no errors.

You must provide either:
     1) --check-skill or
     2) --check-manifest and --use-animdb

The 3 modes of use:

1) Check a skill's animdb references against the skill's npm-installed jibo-anim-db-animations (writes manifest in skill folder)
   $ anim-ref-check --check-skill /path/to/skill

2) Check a skill's animdb references against an arbitrary animDB (writes manifest in skill folder)
   $ anim-ref-check --check-skill /path/to/skill --use-animdb /path/to/animdb.json

3) Check the references in a manifest against an arbitrary animDB
   $ anim-ref-check --check-manifest /path/to/skill/animdb-manifest.json --use-animdb /path/to/animdb.json`);

    process.exit(0);
}

export default function cli() {
    const argv = process.argv.slice(2);
    if (argv.length === 0) {
        usage();
    }
    const args:any = minimist(argv, {
        string: ['skill', 'animdb', 'manifest'],
        boolean: ['verbose', 'no-manifest', 'no-report'],
        alias: {
            'check-skill': 'skill',
            'check-manifest': 'manifest',
            'use-animdb': 'animdb',
            s: 'skill',
            a: 'animdb',
            m: 'manifest',
            v: 'verbose',
            M: 'no-manifest',
            R: 'no-report',
        },
        default: {
            verbose: false,
            'no-manifest': false,
            'no-report': false,
        }
    });

    if (!!args.skill === !!args.manifest) {
        console.log('Error: a skill or manifest must be specified, but not both.');
        usage();
    }

    const result = AnimRefChecker.exec(args);

    result.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        process.exit(0);
    });

    result.on('log', (message) => {
        if (args.verbose) {
            console.log(chalk.green(message));
        }
    });

    result.on('warn', (message) => {
        if (args.verbose) {
            console.log(chalk.yellow(message));
        }
    });

    result.on('lintError', (err) => {
        console.error(chalk.red(err));
    });
}