// External dependencies
import path = require('path');
import fs = require('fs');
import escodegen = require('escodegen');
import esprima = require('esprima');
import findRoot = require('find-root');
import estraverse = require('estraverse');
import chalk = require('chalk');
import {
    ArrayExpression,
    ObjectExpression,
    FunctionExpression,
    LiteralExpression,
    ArrowFunctionReturnRequire
} from 'jibo-esexpressions';
import cli from './cli';
import core from './core';
import versions from './versions';

/**
 * Converts a raw JSON data structure into a JavaScript module.
 * ```
 * import {Behaviorify} = require('jibo-dev');
 * const bt = new Behaviorify('/path/to/custom.bt');
 * console.log(bt.exec());
 * ```
 * @class Behaviorify
 * @param {String} filename The file name if the first argument is an Object.
 * @param {Object} [data] The `.bt` or `.flow` file data or path to file.
 */
class Behaviorify {

    /**
     * Current version of the behavior tree format
     * @name Behaviorify.CURRENT_VERSION
     * @type {Number}
     */
    static CURRENT_VERSION:number = 1;

    public data:any;
    public filename:string;

    /**
     * Browserify transform
     * @method Behaviorify.transform
     * @private
     * @param {String} filename File name.
     * @param {String} source Buffer from source file.
     * @return {String} Output JavaScript module buffer.
     */
    public static transform(filename:string, source:string):any {
        const data = JSON.parse(source);
        //substitute the behaviorPaths
        const keys = Object.keys(data);
        for (let i = 0; i < keys.length; i++) {
            const key = keys[i];
            if (data[key].class === 'Subtree') {
                const behaviorPath = data[key].options.behaviorPath;
                data[key].options.behaviorPath = [
                    "() => {",
                    "    return require('" + behaviorPath + "');",
                    "}"
                ];
            }
        }
        const result = new Behaviorify(filename, data);
        return result.exec();
    }

    /**
     * Run behaviorify for the commandline.
     * @method Behaviorify.cli
     * @private
     */
    public static cli(): void {
        cli();
    }

    /**
     * The core classes.
     * @method Behaviorify.core
     * @return {Map} Collection of core behavior and decorators.
     */
    public static get core(): typeof core {
        return core;
    }

    constructor(filename:string, data?:any) {

        /**
         * Path to the filename.
         * @name Behaviorify#filename
         * @type {String}
         */
        this.filename = path.resolve(filename);

        // First argument can be a file path
        if (!data) {
            data = JSON.parse(fs.readFileSync(this.filename, 'utf8'));
        }

        // Get the version of the meta field, add backward compatibility
        // for bt files that were created before versioning
        data.meta = data.meta || { version: 0 };

        /**
         * JSON data for a .flow or .bt file
         * @name Behaviorify#data
         * @type {Object}
         */
        this.data = data;

        // Update old versions of the tree
        this.update();
    }

    /**
     * Update the raw tree with deprecations.
     * @method Behaviorify#update
     */
    update() {

        // Massage the JSON tree to provide forward compatibility
        while(this.data.meta.version < Behaviorify.CURRENT_VERSION) {
            versions["version" + this.data.meta.version](this.data);
            this.data.meta.version++;
        }
    }

    /**
     * Convert the object.
     * @method Behaviorify#exec
     * @param {Object} [options] - Options.
     * @param {Boolean} [options.noRequirification] if true, the subflow/subtree references are left untouched.
     * @return {String} Resulting buffer JavaScript file.
     */
    exec(options?:any):string {

        // Create a new template everytime
        let tree:any = esprima.parse(this.readFile('templates/tree.js'));
        let treeObject = new ObjectExpression(
            tree.body[tree.body.length - 1]
                .expression
                .right
                .body
                .body[0]
                .argument
                .properties
            );

        let isRequirifying = !options || !options.noRequirification;
        let ids:string[] = Object.keys(this.data);

        for(let i = 0; i < ids.length; i++) {

            let id:string = ids[i];

            // Ignore the meta information
            if (id === "meta") {
                let meta = this.data[id];
                let metaExpression:ObjectExpression = new ObjectExpression();
                Object.keys(meta).forEach((key:string):void => {
                    metaExpression.addKeyValue(key, LiteralExpression(meta[key]));
                });
                treeObject.addKeyValue('meta', metaExpression.expression);
                continue;
            }

            let nodeDef = this.data[id];
            let hasFunction = false;
            let hasSelf = false;

            let objectExpression = new ObjectExpression();
            objectExpression.addKeyValue('id', LiteralExpression(id));

            if (nodeDef.name) {
                objectExpression.addKeyValue('name', LiteralExpression(nodeDef.name));
            }

            if (nodeDef.parent) {
                objectExpression.addKeyValue('parent', LiteralExpression(nodeDef.parent));
            }

            if (nodeDef['asset-pack']) {
                objectExpression.addKeyValue('asset-pack', LiteralExpression(nodeDef['asset-pack']));
            }

            if (nodeDef.transitions) {
                let arrayExpression = new ArrayExpression();
                for(let k = 0; k < nodeDef.transitions.length; k++) {
                    let transition = nodeDef.transitions[k];
                    let transitionExpression = new ObjectExpression();
                    Object.keys(transition).forEach((key) => {
                        transitionExpression.addKeyValue(key, LiteralExpression(transition[key]));
                    });
                    arrayExpression.push(transitionExpression.expression);
                }
                objectExpression.addKeyValue('transitions', arrayExpression.expression);
            }

            if (nodeDef.exceptions) {
                let arrayExpression = new ArrayExpression();
                for(let k = 0; k < nodeDef.exceptions.length; k++) {
                    let exceptions = nodeDef.exceptions[k];
                    let exceptionsExpression = new ObjectExpression();
                    Object.keys(exceptions).forEach((key) => {
                        exceptionsExpression.addKeyValue(key, LiteralExpression(exceptions[key]));
                    });
                    arrayExpression.push(exceptionsExpression.expression);
                }
                objectExpression.addKeyValue('exceptions', arrayExpression.expression);
            }

            objectExpression.addKeyValue('class', LiteralExpression(nodeDef.class));
            if (nodeDef.children) {
                let arrayExpression = new ArrayExpression();
                for(let k = 0; k < nodeDef.children.length; k++) {
                    arrayExpression.push(LiteralExpression(nodeDef.children[k]));
                }
                objectExpression.addKeyValue('children', arrayExpression.expression);
            }

            if (nodeDef.skipped) {
                objectExpression.addKeyValue('skipped', LiteralExpression(nodeDef.skipped));
            }

            if (nodeDef.decorators) {
                let arrayExpression = new ArrayExpression();
                for(let k = 0; k < nodeDef.decorators.length; k++) {
                    arrayExpression.push(LiteralExpression(nodeDef.decorators[k]));
                }
                objectExpression.addKeyValue('decorators', arrayExpression.expression);
            }

            if (nodeDef.options) {
                let optionsExpression = new ObjectExpression();
                for (let k in nodeDef.options) {
                    let value = nodeDef.options[k];
                    if(Array.isArray(value)) {
                        value = nodeDef.options[k] = value.join("\n");
                    }
                    if(typeof value === 'string' && (value.indexOf('function') === 0 || value.indexOf('=>') >= 0)) {
                        hasFunction = true;
                        try {
                            let code = value;
                            let parsed:any = esprima.parse(code);
                            estraverse.traverse(parsed, {
                                enter: (node, parent) => {
                                    if(node.name && node.name === 'self' &&
                                        parent.object && parent.object.name === 'self') {
                                        hasSelf = true;
                                    }
                                }
                            });


                            if(parsed.body[0].type === 'ExpressionStatement') {
                                parsed = parsed.body[0].expression;
                            }
                            else {
                                parsed = parsed.body[0];
                            }
                            optionsExpression.addKeyValue(k, parsed);
                        }
                        catch(e) {
                            const localFilename = this.filename.replace(process.cwd() + '/', '');
                            console.error(chalk.underline(localFilename));
                            console.error(chalk.red.bold('  error'), e.message);
                            console.error(chalk.gray('  ' + value.replace(/\t/g, '  ').replace(/\n/g, '\n  ')));
                            console.error();
                        }
                    }
                    else if (isRequirifying && nodeDef.class === 'Subtree' && k === 'behaviorPath') {
                        optionsExpression.addKeyValue(k, ArrowFunctionReturnRequire(value));
                    }
                    else if (isRequirifying && nodeDef.class === 'Flow.Subflow' && k === 'subflowId') {
                        optionsExpression.addKeyValue(k, ArrowFunctionReturnRequire(value));
                    }
                    else if (isRequirifying && nodeDef.class === 'Flow.Subtree' && k === 'behaviorPath') {
                        optionsExpression.addKeyValue(k, ArrowFunctionReturnRequire(value));
                    }
                    else {
                        optionsExpression.addKeyValue(k, LiteralExpression(value));
                    }
                }
                objectExpression.addKeyValue('options', optionsExpression.expression);
            }

            if (hasFunction) {
                treeObject.addKeyValue(id, FunctionExpression(objectExpression.expression, hasSelf));
            }
            else {
                treeObject.addKeyValue(id, objectExpression.expression);
            }
        }

        return escodegen.generate(tree);
    }

    /**
     * Clear and don't use after this.
     * @method Behaviorify#dispose
     * @private
     */
    public dispose(): void {
        this.data = null;
        this.filename = null;
    }

    /**
     * Simple utility to read a file.
     * @method Behaviorify#readFile
     * @private
     * @param {String} file The local file path.
     * @return {String} Contents of the file.
     */
    private readFile(file:string):string {
        const rootPath = findRoot(__dirname);
        return fs.readFileSync(path.resolve(rootPath, file), 'utf8');
    }
}

export default Behaviorify;
