import minimist = require('minimist');
import chalk = require('chalk');
import FlowLint from './FlowLint';

export default function cli() {
    
    const args:any = minimist(process.argv.slice(2), {
        string: ['dir'],
        boolean: ['verbose'],
        alias: {
            v: 'verbose',
            d: 'dir',
        },
        default: {
            verbose: false,
        }
    });

    const result = FlowLint.exec(args.dir, args.verbose);

    result.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        process.exit(0);
    });

    result.on('log', (message) => {
        console.log(chalk.green(message));
    });

    result.on('lintError', (err) => {
        console.error(chalk.red(err));
    });
}