import fs = require('fs');
import path = require('path');
import cli from './cli';
import {EventEmitter} from 'events';
import {FlowRootFactory} from 'jibo-flow-core';
import glob = require('glob');

/**
 * Statically check a `.flow` file and its dependencies for inconsistencies and missing resources.
 * ```
 * import {FlowLint} from 'jibo-dev';
 * var linter = new FlowLint(__dirname, '/full/path/to/file.flow');
 * linter.run();
 * console.log(linter.getErrorReport());
 * ```
 * @class FlowLint
 * @param {string} projectRoot Path to the skill's project-level directory.
 * @param {string} uri Path to the `.flow` file.
 */
export class FlowLint {

    public procedures:{ [key:string]:any };
    public flowRoot:any;
    private errors:Error[];

    /**
     * Command-line tool for validating a directory or single flow file.
     * @method FlowLint.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    /**
     * Command-line tool for validating a directory or single flow file.
     * @method FlowLint.exec
     * @param {String} dir Directory containing flow files
     * @param {Boolean} [verbose=false] If we should load
     * @return {EventEmitter} Emits 'lintError', 'end' and 'log' event
     */
    static exec(dir:string, verbose?:boolean): EventEmitter {
        const result = new EventEmitter();
        process.nextTick(() => {
            const files = glob.sync(path.join(dir, '**/*.flow'));
            if (!files.length) {
                result.emit('end', 'Must provide files to process');
                return;
            }
            files.forEach(function(filename){
                const uri:string = path.resolve(filename);
                const linter:FlowLint = new FlowLint(process.cwd(), uri);
                linter.run();
                const report:string = linter.getErrorReport();
                if (report) {
                    result.emit('lintError', report);
                }
                else if (verbose) {
                    result.emit('log', 'Flow is clean ' + filename);
                }
            });
            result.emit('end');
        });
        return result;
    }

    constructor(public projectRoot:string, public uri:string) {
        this.procedures = {};
        this.errors = [];
        this.flowRoot = FlowRootFactory.create(this.uri);
    }

    /**
     * Run the preflight check.
     * @method FlowLint#run
     */
    public run(): void {
        this.loadProcedures();
        this.checkProcedures();
    }

    /**
     * Write discovered errors to the given file.
     * @method FlowLint#writeReportToFile
     * @param {string} filename
     */
    public writeReportToFile(filename:string): void {
        let report = this.getErrorReport();
        fs.writeFileSync(filename, `Preflight Report for ${this.uri}\n` + report);
    }

    /**
     * Format all the discovered errors into a report.
     * @method FlowLint#getErrorReport
     * @returns {string} Report of all discovered errors.
     */
    public getErrorReport():string {
        let report = '';
        let currentProcedure = '';
        for (let error of this.getSortedErrors()) {
            if (error.procedure.name !== currentProcedure) {
                report += `\nErrors found in procedure '${error.procedure.name}':\n`;
                currentProcedure = error.procedure.name;
            }
            if (error.isActivity) {
                let name = error.activity.name ? `'${error.activity.name}' ` : '';
                report += `   ${error.code} ${error.activity.class} ${name}${error.message}\n`;
            } else {
                report += `   ${error.code} ${error.message}\n`;
            }
        }
        return report;
    }

    /**
     * Recursively load all the procedures reachable from the preflighted procedure.
     * @method FlowLint#loadProcedures
     * @private
     */
    private loadProcedures() {
        let startProcedure = this.flowRoot.getStartProcedure();
        this.loadProcedure(startProcedure);
    }

    /**
     * Load a procedure and all its dependents.
     * @method FlowLint#loadProcedure
     * @private
     * @param {Procedure} procedure
     */
    private loadProcedure(procedure:any) {
        if (procedure.uri in this.procedures) {
            return;
        }
        this.procedures[procedure.uri] = procedure;
        this.loadSubflows(procedure);
        this.loadReturnValues(procedure);
    }

    /**
     * Recursively load all the procedures reachable from the preflighted procedure.
     * @method FlowLint#loadProcedures
     * @private
     * @param {Procedure} procedure
     */
    private loadSubflows(procedure:any) {
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            if (activity.class === 'Flow.Subflow') {
                try {
                    let subflow = this.flowRoot.loadProcedure(procedure.uri, activity.options.subflowId);
                    // Stash the subflow procedure in the activity for convenience at check time.
                    (<any>activity).subflow = subflow;
                    this.loadProcedure(subflow);
                } catch (e) {
                    this.addActivityError(activity, `references a non-existent flow file '${activity.options.subflowId}'`, 'MISSING SUBFLOW');
                    (<any>activity).subflow = undefined;
                }
            }
        }
    }

    /**
     * Gather up all the different transition values that a procedure returns to its parent via Flow.End.
     * @method FlowLint#loadReturnValues
     * @private
     * @param {Procedure} procedure
     */
    private loadReturnValues(procedure:any) {
        (<any>procedure).validReturns = [];
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            if (activity.class === 'Flow.End') {
                let transition = undefined;
                // Actually try and execute the getTransition() method of the Flow.End shape.
                try {
                    let getTransition = activity.options.getTransition;
                    if (typeof getTransition === typeof []) {
                        getTransition = getTransition.join(' ');
                    }
                    getTransition = `return (${getTransition});`;
                    transition = (new Function(getTransition))()();
                } catch (e) {
                    // Skip anything we can't evaluate statically.
                    continue;
                }
                (<any>procedure).validReturns.push(transition || activity.name || '');
            }
        }
    }

    /**
     * Check all the procedures found during loading.
     * @method FlowLint#checkProcedures
     * @private
     */
    private checkProcedures() {
        for (let procedure of this.getSortedProcedures()) {
            this.checkProcedure(procedure);
        }
    }

    /**
     * Get a sorted list of all the procedures that have been loaded.
     * @method FlowLint#getSortedProcedures
     * @private
     */
    private getSortedProcedures() {
        let procedures = [];
        for (let procedureId in this.procedures) {
            procedures.push(this.procedures[procedureId]);
        }
        procedures.sort((a, b) => {
            return a.name.localeCompare(b.name);
        });
        return procedures;
    }

    /**
     * Check a procedure for consistency and missing resources.
     * @method FlowLint#checkProcedure
     * @private
     * @param {Procedure} procedure
     */
    private checkProcedure(procedure:any) {
        this.checkTransitionCounts(procedure);
        this.checkTransitionValues(procedure);
        this.checkStartValidity(procedure);
        this.checkMimReferences(procedure);
    }

    /**
     * Ensure that correct number of transitions are used for each type of activity.
     * @method FlowLint#checkTransitionCounts
     * @private
     * @param {Procedure} procedure
     */
    private checkTransitionCounts(procedure:any) {
        // check each activity's outbound transitions
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            let transitions = activity.transitions.length + activity.exceptions.length;
            if (transitions === 0
                && activity.class !== 'Flow.Throw'
                && activity.class !== 'Flow.Comment'
                && activity.class !== 'Flow.End') {
                // TODO figure out if we need this:
                //this.addActivityError(activity, 'has no outbound transitions', 'NO OUTBOUND');
            }
            if (transitions !== 1 &&
                (activity.class === 'Flow.Begin'
                || activity.class === 'Flow.Parallel-Begin'
                || activity.class === 'Flow.Catch')) {
                this.addActivityError(activity, 'has more than one transition', 'MULTIPLE OUTBOUND');
            }
        }

        // check that each activity's outbound transition values are unique
        let outbounds = {};
        for (let transition of procedure.connections) {
            if (!(transition.frm in outbounds)) {
                outbounds[transition.frm] = {};
            }
            if (transition.value in outbounds[transition.frm]) {
                let activity = procedure.activities[transition.frm];
                this.addActivityError(activity, `has duplicate outbound transitions values: "${transition.value}"`, 'DUP OUTBOUND');
            }
            outbounds[transition.frm][transition.value] = true;
        }
    }

    /**
     * Ensure that values returned from an activity (currently just Subflows) will match one of its outbound transitions.
     * @method FlowLint#checkTransitionValues
     * @private
     * @param {Procedure} procedure
     */
    private checkTransitionValues(procedure:any) {
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            if (activity.class === 'Flow.Subflow' && (<any>activity).subflow) {
                for (let retval of (<any>activity).subflow.validReturns) {
                    let valid = false;
                    for (let transition of activity.transitions) {
                        if (retval === transition.value || transition.value === '') {
                            // We have found a transition that will match the return value.
                            valid = true;
                            break;
                        }
                    }
                    if (!valid) {
                        this.addActivityError(activity, `has no transition matching the value '${retval}' being returned from ${activity.options.subflowId}`, 'NO MATCHING TRANSITION');
                    }
                }
            }
        }
    }

    /**
     * Ensure that the procedure has the correct number of Flow.Begin activities.
     * @method FlowLint#checkStartValidity
     * @private
     * @param {Procedure} procedure
     */
    private checkStartValidity(procedure:any) {
        let beginCount = 0;
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            if (activity.class === 'Flow.Begin') {
                beginCount++;
            }
        }
        if (beginCount < 1) {
            this.addProcedureError(procedure, "Procedure has no Flow.Begin activity", 'MISSING BEGIN');
        }
        if (beginCount > 1) {
            this.addProcedureError(procedure, "Procedure has more than one Flow.Begin activity", 'MULTIPLE BEGIN');
        }
    }

    /**
     * Ensure that the resources referenced by each mim in the procedure are present.
     * @method FlowLint#checkMimReferences
     * @private
     * @param {Procedure} procedure
     */
    private checkMimReferences(procedure:any) {
        for (let activityId in procedure.activities) {
            let activity = procedure.activities[activityId];
            if (activity.class.startsWith('Mim')) {
                this.checkMim(activity);
            }
        }
    }

    /**
     * Ensure that a mim activity's referenced files are present (mim file, rule file, animation files).
     * @method FlowLint#checkMim
     * @private
     * @param {Activity} activity
     */
    private checkMim(activity:any) {
        // Here we skip mim-checking on activities that don't have a static mim path:
        if (!activity.options.mimPath || activity.options.getMimPath) {
            return;
        }
        let mimPath = path.resolve(this.projectRoot, activity.options.mimPath);
        if (!fs.existsSync(mimPath) || !fs.statSync(mimPath).isFile()) {
            this.addActivityError(activity, `references non-existent Mim file '${mimPath}'`, 'MISSING MIM');
            return;
        }
        let mim;
        try {
            mim = JSON.parse(fs.readFileSync(mimPath, 'utf8'));
        } catch (e) {
            this.addActivityError(activity, `references Mim file '${mimPath}' with bad JSON`, 'BAD MIM');
            return;
        }
        // Poor-mans xml parse: Simply look for "path=" attributes in the string and report if they exist as files.
        let takenIds:{[id:string]:boolean} = {};
        for (let prompt of mim.prompts) {
            let match, re = /path=['"]([^'"]*)['"]/gi; // The (inner match) is the filename.
            while (match = re.exec(prompt.prompt)) {
                let animFile = match[1];
                let animPath = path.resolve(this.projectRoot, 'animations', animFile);
                if (!fs.existsSync(animPath)) {
                    this.addActivityError(activity, `prompt animation '${animFile}' in '${activity.options.mimPath}' does not exist`, 'MISSING ANIMATION');
                }
            }
            //also, check to see that every prompt has a unique id
            if (!prompt.prompt_id) {
                this.addActivityError(activity, `A prompt in '${activity.options.mimPath}' does not have an id`, 'MISSING PROMPT ID');
            } else if(takenIds[prompt.prompt_id]) {
                this.addActivityError(activity, `Prompt id '${prompt.prompt_id}' in '${activity.options.mimPath}' is not unique`, 'DUPLICATE PROMPT ID');
            } else {
                takenIds[prompt.prompt_id] = true;
            }
        }
    }

    /**
     * Accumulate an error referring to a procedure.
     * @method FlowLint#addProcedureError
     * @private
     * @param {Procedure} procedure
     * @param {string} message
     * @param {string} code
     */
    private addProcedureError(procedure:any, message:string, code:string) {
        this.errors.push(new Error(procedure, message, code));
    }

    /**
     * Accumulate an error referring to an activity.
     * @method FlowLint#addProcedureError
     * @private
     * @param {Activity} activity
     * @param {string} message
     * @param {string} code
     */
    private addActivityError(activity:any, message:string, code:string) {
        this.errors.push(new Error(activity, message, code));
    }

    /**
     * Sort the errors by procedure name, error code, activity type, and activity name.
     * @method FlowLint#getSortedErrors
     * @private
     * @returns {Error[]}
     */
    private getSortedErrors() {
        this.errors.sort((a:Error, b:Error) => {
            if (a.procedure.name === b.procedure.name) {
                if (a.isActivity === b.isActivity) {
                    // Sort errors within a procedure by Error Code, Class and Name
                    let akey = a.code + a.activity.class + a.activityName;
                    let bkey = b.code + b.activity.class + b.activityName;
                    return akey.localeCompare(bkey);
                }
                // sort procedure errors before activity errors.
                return +a.isActivity - +b.isActivity;
            }
            return a.procedure.name.localeCompare(b.procedure.name);

        });
        return this.errors;
    }
}

/**
 * Hold one preflight error.
 * @class Error
 * @private
 */
class Error {
    public isActivity:boolean;
    public procedure:any;
    public activityName:string;
    public activity:any;
    public message:string;
    public code:string;

    constructor(activityOrProcedure:any, message:string, code:string) {
        if (activityOrProcedure.procedure !== undefined) {
            this.isActivity = true;
            this.procedure = activityOrProcedure.procedure;
            this.activityName = activityOrProcedure.name;
            this.activity = activityOrProcedure;
        } else {
            this.isActivity = false;
            this.procedure = activityOrProcedure;
            this.activityName = '';
            this.activity = null;
        }
        this.message = message;
        this.code = code;
    }
}

export default FlowLint;
