import fs = require('fs');
import path = require('path');
import cli from './cli';
import {EventEmitter} from 'events';
import glob = require('glob');
import { api, Animation } from 'jibo-anim-db';
import chalk = require('chalk');
import uuid = require('uuid');

const JiboKeyframeInfo = require('jibo-keyframes').JiboKeyframeInfo;
const resolve = require('resolve');

/**
 * Statically check the validity of various asset references in all the keys files in a skill's animation folder.
 * ```
 * import {KeysRefChecker} from 'jibo-dev';
 * ```
 * @class KeysRefCheckerer
 * @param {string} projectRoot Path to the skill's project-level directory.
 */

export class KeysRefChecker extends EventEmitter {
    public verbose: boolean;
    private errors: Error[] = [];
    private noReport: boolean;
    private skipUnderscores: boolean;
    private skillDir: string;
    private animdb: string;
    private fixIds: boolean;

    /**
     * Command-line tool for validating the asset references in a skill's keys files.
     * @method KeysRefChecker.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    /**
     * Command-line tool entrypoint
     * @method KeysRefChecker.exec
     * @param {any} args Options for controlling the checker.
     * @return {EventEmitter} Emits 'lintError', 'end' and 'log' event
     */
    static exec(args): EventEmitter {
        const refChecker = new KeysRefChecker(args);
        refChecker.run();
        return refChecker;
    }

    constructor(public args: any) {
        super();
        this.noReport = args['no-report'];
        this.skillDir = args.skill;
        this.animdb = args.animdb;
        this.skipUnderscores = args['skip-underscores'];
        this.verbose = args.verbose;
        this.fixIds = args['fix-nonunique-layers'];
    }

    /**
     * Main entry point for execution. This loads the required files and proceeds through all the checks.
     * @method KeysRefChecker.run
     */
    public run():void {
        // Init animation DB
        this.init().catch((err) => {
            if (`${err}`.indexOf('jibo-anim-db-animations') !== -1) {
                console.log(chalk.red('Skill has no animation database -- animDB references will fail when checked.'));
            } else {
                console.log(chalk.red('Failed to initialize animation database -- animDB references will fail when checked'), err);
            }
        }).then(() => {
            this.loadRefsFromSkill(()=>this.runChecks());
        });
    }

    /**
     * Write discovered errors to the given file.
     * @method KeysRefChecker#writeReportToFile
     * @param {string} filename
     */
    public writeReportToFile(filename: string, title: string): void {
        const report = this.getErrorReport();
        fs.writeFileSync(filename, `AnimDB Reference Report for ${title}\n` + report);
    }

    /**
     * Format all the discovered errors into a report.
     * @method KeysRefChecker#getErrorReport
     * @returns {string} Report of all discovered errors.
     */
    public getErrorReport():string {
        let lines = [];

        for (const error of this.errors) {
            let line = `${error.code}: ${error.message} in ${error.location}`;
            lines.push(line);
        }
        lines.sort();
        lines.push(''); // force all lines to print
        let report = '';
        let count = 0;
        let prior = lines[0];
        // Here we print each line with a tally in front of duplicated lines.
        for (const line of lines) {
            if (line !== prior) {
                report += `${count === 1 ? ' ' : count} ${prior}\n`;
                prior = line;
                count = 0;
            }
            count++;
        }
        return report;
    }

    public getFancyErrorReport():string {
        let report = '';
        let location = '';
        // Group all the errors in the same file/activity together
        this.errors.sort((a:Error,b:Error)=>a.location.localeCompare(b.location));
        for (const error of this.errors) {
            if (error.location !== location) {
                report += `\nErrors found in '${error.location}':\n`;
                location = error.location;
            }
            report += `${error}\n`;
        }
        return report;
    }

    /**
     * Accumulate an error referring to an activity.
     * @method KeysRefChecker#addProcedureError
     * @private
     * @param {Activity} activity
     * @param {string} message
     * @param {string} code
     */
    public addError(location:any, message:string, code:string) {
        this.errors.push(new Error(location, message, code));
    }

    public resolve(wanted) {
        const dir = resolve.sync(wanted, { basedir: this.skillDir });
        return path.dirname(dir);
    }


    private runChecks() {
        const report = this.getErrorReport();
        if (report) {
            this.emit('lintError', report);
        }
        this.emit('end');
    }

    // Load the optional animdb if provided, otherwise the skill's installed animation DB.

    private async init(): Promise<void> {
        let animDBpath = this.animdb;
        if (!animDBpath) {
            let adaPath = this.resolve('jibo-anim-db-animations');
            animDBpath = adaPath && path.resolve(adaPath, 'animdb.json');
        }
        return api.init(null, animDBpath);
    }

    private loadRefsFromSkill(cb) {
        const checker = new KeysChecker(this, this.skillDir);
        checker.checkSkillRefs();
        this.emit('status', `Checked ${checker.checkedFiles} files`);
        if (checker.fixedFiles) {
            this.emit('status', `Fixed ${checker.fixedFiles} files`);
        }    
        cb();
    }
}

class KeysChecker {
    public skillDir: string;
    public checkedFiles = 0;
    public fixedFiles = 0;
    private errors: Error[];
    private extracted = {};
    private layerIds = {};

    constructor(public refChecker, dir) {
        this.skillDir = path.resolve(dir);
        this.errors = [];
    }

    /**
     * Check all the keys files in the animations folder of the skill.
     */    
    public checkSkillRefs() {
        let keysPath = path.resolve(this.skillDir, 'animations/*' + '*/*.keys');
        const files = glob.sync(keysPath);
        if (!files.length) {
            this.refChecker.emit('log', `No keys found in ${this.skillDir}/animations`);
        }
        for (const filename of files) {
            this.checkFileRef(filename);
        }
    }

    /**
     * Check all the layers of the given keys file to ensure all the referenced assets are present.
     * @param filename 
     */    
    public checkFileRef(filename): any {
        if (filename in this.extracted || (this.refChecker.skipUnderscores && filename.indexOf('/_') !== -1)) {
            return;
        }
        this.extracted[filename] = true;
        if (this.refChecker.verbose) {
            this.refChecker.emit('log', `Checking ${filename}`);
        }

        let keys;
        try {
            keys = JSON.parse(fs.readFileSync(filename, 'utf8'));
        } catch (e) {
            this.refChecker.addError(filename, `references Keys file '${filename}' with bad JSON`, 'JSON-PARSE');
            return;
        }

        // Bring the keys file up to the latest spec.
        JiboKeyframeInfo.onLoad(keys);
        this.refChecker.emit('checkFileRefs', filename);

        this.uniqifyLayerIds(filename, keys);
        this.checkedFiles++;

        let checked = {};

        for (let layer of keys.layers) {
            switch (layer.type) {
                case 'Overlay Texture':
                case 'Eye Texture':
                    for (let keyframe of layer.keyframes) {
                        let src = keyframe.value.Texture;
                        if (src === '') {
                            // blank texture paths are legal.
                            continue;
                        }
                        let apath = this.resolveAssetPath(src);
                        this.checkPath(checked, { apath, filename, type: layer.type, src });
                    }
                    break;

                case 'Audio Event':
                    for (let keyframe of layer.keyframes) {
                        let src = keyframe.value.AudioEvent.file;
                        let apath = this.resolveAssetPath(src, 'audio');
                        this.checkPath(checked, { apath, filename, type: layer.type, src });
                    }
                    break;

                case 'Pixi':
                    for (let keyframe of layer.keyframes) {
                        let src = keyframe.value.Pixi;
                        let apath = this.resolveAssetPath(src, 'timelines');
                        if (this.checkPath(checked, { apath, filename, type: layer.type, src })) {
                            let refs = this.getPixiReferences(apath);
                            for (let ref of refs) {
                                let apath = this.resolveAssetPath(ref, 'timelines');
                                this.checkPath(checked, { apath, filename, type: 'Pixi-ref', src: ref });
                                if (ref.endsWith('.json')) {
                                    let jref = this.getJsonReference(apath);
                                    if (jref) {
                                        let aref = path.resolve(path.dirname(apath), jref);
                                        this.checkPath(checked, { apath: aref, filename, type: 'Pixi-image-ref', src: jref });
                                    }
                                }
                            }
                        }
                    }
                    break;
                    
                case 'Reference':
                    for (let keyframe of layer.keyframes) {
                        let apath = this.getReferencedPath(filename, keyframe);
                        if (apath) {
                            let mode = keyframe.value.ReferenceMode.value;
                            if (this.checkPath(checked, {
                                apath,
                                filename,
                                type: 'Reference',
                                mode,
                                src: keyframe.value.KeysFileReference[mode]
                            })) {
                                this.checkFileRef(apath);
                            }
                        }
                    }
                    break;
            }
        }
    }

    /**
     * Convert the anim reference in the given keys file, at the given keyframe, into an absolute file path.
     */    
    public getReferencedPath(filename, keyframe) {
        let mode = keyframe.value.ReferenceMode.value;
        let src = keyframe.value.KeysFileReference[mode];
        let apath:string;
        if (mode === 'name') {
            let anim:Animation;
            try {
                anim = api.getAnimByName(src);
            } catch (e) { /* */ }
            if (anim) {
                apath = path.resolve(anim.resourceRoot, anim.meta.path);
            } else {
                this.refChecker.addError(filename, `Animation name "${src}" not found in animation DB`, 'MISSING-ANIM');
            }
        } else {
            apath = path.resolve(path.dirname(filename), src);
        }
        return apath;
    }

    /**
     * Check for the existence of a non-blank path (only once) and report an error if it's missing.
     */
    public checkPath(checked, info) {
        let apath = info.apath;
        if (apath.indexOf('/_') !== -1 && this.refChecker.skipUnderscores === true) {
            this.refChecker.addError(info.filename, `${apath}`, 'UNDERSCORE REF');
        }
        if (!(apath in checked)) {
            let success = true;
            if (apath && (!fs.existsSync(apath) || !fs.statSync(apath).isFile())) {
                success = false;
                this.refChecker.addError(info.filename, `'${info.src} (full: ${apath})'`, `missing ${info.type}`.toUpperCase());
            }
            checked[apath] = success;
            this.refChecker.emit('checkPath', apath, success);
        }
        return checked[apath];
    }

    /*
     * Fish out references to json or png assets within Javascript files on lines that look like this:
     *       "emoji_gas_atlas_1": "images/emoji_gas_atlas_1.json"
     */
    public getPixiReferences(filename) {
        this.refChecker.emit('checkPixiRefs', filename);
        let refs = [];
        let data;
        try {
            data = fs.readFileSync(filename, 'utf8');
        } catch (e) {
            console.log('failed to open file', filename);
            return refs;
        }
        for (let line of data.split('\n')) {
            line = line.trim();
            if (line.indexOf('"images/') !== -1) {
                let ref = line.replace(/^.*"(images\/.*?)".*$/, '$1');
                refs.push(ref);
            }
        }
        return refs;
    }

    // Get the (possibly non-existent) reference to an image in a Pixi JSON file.

    public getJsonReference(uri) {
        this.refChecker.emit('checkJsonRefs', uri);
        let body;
        try {
            body = JSON.parse(fs.readFileSync(uri, 'utf8'));
        } catch (e) {
            this.refChecker.addError(uri, `Pixi JSON file '${uri}' could not be loaded and parsed`, 'JSON-PARSE');
        }
        let ref = body && body.meta && body.meta.image;
        return ref;
    }

    // Convert possible asset-pack style reference into full path

    public resolveAssetPath(src:string, middle?:string) {
        let parts = src.split('://');
        middle = middle || '';
        if (parts.length > 1) {
            let dir = this.refChecker.resolve(parts[0]);
            let final = path.resolve(dir, middle, parts[1]);
            return final;
        } else {
            return path.resolve(this.skillDir, middle, src);
        }
    }

    public uniqifyLayerIds(filename, keys) {
        if (this.refChecker.fixIds) {
            let dirty = false;
            for (let layer of keys.layers) {
                if (layer.type === 'Reference' && layer.id in this.layerIds) {
                    dirty = true;
                    layer.id = uuid.v4().replace(/-/g,"");
                }
                this.layerIds[layer.id] = true;
            }
            if (dirty) {
                this.fixedFiles++;
                fs.writeFileSync(filename, JSON.stringify(keys, null, '    '), 'utf8');
                this.refChecker.emit('log', `Making unique layer IDs in ${filename}`);
            }
        }
    }
}

/**
 * Hold one preflight error.
 * @class Error
 * @private
 */
class Error {
    constructor(public location:any, public message:string, public code:string) {
    }
    toString() {
        return `   ${this.code} ${this.message}`;
    }
}

export default KeysRefChecker;
