import minimist = require('minimist');
import chalk = require('chalk');
import MimFixer from './MimFixer';

export default function cli() {
    const args:any = minimist(process.argv.slice(2), {
        string: ['target'],
        boolean: ['verbose'],
        alias: {
            v: 'verbose',
            t: 'target',
        },
        default: {
            verbose: false,
        }
    });

    const fixer = new MimFixer();

    fixer.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        process.exit(0);
    });

    fixer.on('log', (message) => {
        console.log(chalk.green(message));
    });

    fixer.on('error', (err) => {
        console.error(chalk.red(err));
    });
    
    fixer.run(args.target, args.verbose);
}