import JiboDev from '../JiboDev';
import tslint from 'gulp-tslint';
import path = require('path');

export default function(gulp, dev:JiboDev) {
    gulp.task('lint', function(){
        return gulp.src(dev.config.app)
            .pipe(tslint({
                configuration: path.resolve(dev.dirname, dev.config.tslint)
            }))
            .pipe(tslint.report());
    });
}
