import GojsBareBonesLoader from './flow/gojs-loader/GojsBareBonesLoader';
import Behaviorify from './Behaviorify';
import chalk = require('chalk');
import path = require('path');

/**
 * API to convert `.flow` files into JavaScript.
 * ```
 * import {Flowify} = require('jibo-dev');
 * const flow = new Flowify('/path/to/custom.flow');
 * console.log(flow.exec());
 * ```
 * @class Flowify
 * @param {String} filename Path and name of the file to compile.
 * @param {Object} [data] The parsed JSON file to load.
 */
export default class Flowify extends Behaviorify {

    /**
     * Browserify transform.
     * @method Flowify.transform
     * @private
     * @param {String} filename File name.
     * @param {String} source Buffer from source file.
     * @return {String} Output JavaScript module buffer.
     */
    public static transform(filename:string, source:string): string {
        const data = JSON.parse(source);
        const nodeDataArray = data.nodeDataArray;
        for (let i = 0; i < nodeDataArray.length; i++) {
            let node = nodeDataArray[i];
            switch (node.class) {
                case 'Flow.Subflow':
                {
                    node.options.subflowId = [
                        "() => {",
                        "    return require('" + node.options.subflowId + "');",
                        "}"
                    ];
                    break;
                }
                case 'Subtree':
                {
                    node.options.behaviorPath = [
                        "() => {",
                        "    return require('" + node.options.behaviorPath + "');",
                        "}"
                    ];
                    break;
                }
            }
        }
        const result = new Flowify(filename, data);
        return result.exec();
    }

    constructor(filename:string, data?:{[id:string]:any}) {

        if (path.extname(filename) !== '.flow') {
            console.error(chalk.red('Flowify cannot handle %s files, only .flow files.'));
            return;
        }

        let procedure;

        if (data) {
            procedure = GojsBareBonesLoader.loadParsedProcedure(filename, data);
        } else {
            procedure = GojsBareBonesLoader.loadProcedure(filename);
        }

        super(filename, procedure.toBehaviorifyable());
    }
}
