import Behaviorify from '../bt-flow/Behaviorify';
import Flowify from '../bt-flow/Flowify';
import path = require('path');
import through = require('through2');
import fs = require('fs');

// Keep a local cache of all the files we process
// so we don't need to rerun everytime
const browserifyCache:{[filename:string]:string} = {};
//also keep track of the last modified time, so that we can rerun files that change when watching
const changeTime:{[filename:string]:number} = {};

/**
 * @description Transform for Browserify to compile `.bt` and `.flow` files into source.
 * ```
 * var browserify = require('browserify');
 * browserify().transform('jibo-dev/browserify-transform');
 * ```
 * ```
 * {
 *     "browserify": {
 *         "transform": [
 *             "jibo-dev/browserify-transform"
 *         ]
 *     }
 * }
 * ```
 * @class BrowserifyTransform
 * @param filename {string} `.bt` or `.flow` file to compile.
 */
export default function BrowserifyTransform(filename) {

    const chunks = [];

    function transform(chunk, encoding, callback) {
        chunks.push(chunk);
        callback();
    }

    function flush(callback) {
        const stream = this;
        // Don't process bt/flow files more than once
        const time: number = fs.statSync(filename).mtime.getTime();
        if (browserifyCache[filename] && time === changeTime[filename]) {
            stream.push(browserifyCache[filename]);
            callback();
        }
        else {
            let result: string;
            const source: string = Buffer.concat(chunks).toString();
            switch(path.extname(filename)) {
                case '.bt': {
                    result = Behaviorify.transform(filename, source);
                    break;
                }
                case '.flow': {
                    result = Flowify.transform(filename, source);
                    break;
                }
                default: {
                    result = source;
                    break;
                }
            }
            browserifyCache[filename] = result;
            changeTime[filename] = time;
            stream.push(result);
            callback();
        }
    }
    return through(transform, flush);
}
