import fs = require('fs');
import path = require('path');
import {EventEmitter} from 'events';
import glob = require('glob');
import cli from './cli';

const CATEGORY_HAS_INDEX = {
    'Entry-Core':false,
    Errors: true,
    Response: false
};

const SUBCATEGORY_ABBREVIATION = {
    Q:'QN',
    AN:'AN',
    NM:'NM',
    NI:'NI',
    HoldReturn:'HR',
    Verbose:'VB',
    Truncated:'TC',
    Thanks:'TX'
};

/**
 * Statically check a `.flow` file and its dependencies for inconsistencies and missing resources.
 * ```
 * import {MimFixer} from 'jibo-dev';
 * var fixer = new MimFixer(path.join(__dirname, 'mims'));
 * linter.run();
 * console.log(linter.getErrorReport());
 * ```
 * @class MimFixer
 */
export default class MimFixer extends EventEmitter {

    public target:string;
    public verbose:boolean;

    /**
     * Command-line tool for validating a directory or single flow file.
     * @method FlowLint.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    constructor() {
        super();
    }

    /**
     * Processes a folder of .mim files or a single file.
     * @method MimFixer#run
     * @param {string} target Path to the skill's folder to fix mims found within, or path to a specific .mim file to run on.
     * @param {boolean} [verbose=false] If extended information should be logged.
     */
    public run(target:string, verbose?:boolean):void {
        if (!target) {
            this.emit('error', 'Must supply a target file or folder');
            this.emit('end');
            return;
        }
        this.target = target;
        this.verbose = !!verbose;
        let getFileNames:Promise<string[]>;
        if (target.endsWith('.mim')) {
            getFileNames = Promise.resolve([target]);
        } else {
            getFileNames = new Promise<string[]>((resolve, reject) => {
                glob(path.join(target, '**/*.mim'), (err, matches) => {
                    if (err) {
                        return reject(err);
                    }
                    resolve(matches);
                });
            });
        }
        getFileNames.then((filenames) => {
            if (!filenames.length) {
                this.emit('end', 'No .mim files found');
            }
            //go run all the mims in sequence
            let handleMims = this.processMim(filenames.shift());
            filenames.forEach((file) => {
                handleMims = handleMims.then(() => {
                    return this.processMim(file);
                });
            });
            //return the long promise chain we just set up
            return handleMims;
        }).catch((err) => {
            this.emit('error', 'Fatal error when processing .mim files: ' + err.message || err);
        }).then(() => {
            this.emit('end');
        });
    }

    private processMim(filename:string):Promise<void> {
        return new Promise<void>((resolve, reject) => {
            fs.readFile(filename, 'utf8', (err, text) => {
                if (err) {
                    this.emit('error', `Error reading file ${filename}: ` + err.message);
                    return resolve();
                }
                let json:any;
                try {
                    json = JSON.parse(text);
                } catch (err) {
                    this.emit('error', `Error parsing file ${filename}: ` + err.message);
                    return resolve();
                }
                if (!json.prompts || !json.prompts.length) {
                    this.emit('error', `File ${filename} has no prompts!`);
                    return resolve();
                }
                const mimName = path.basename(filename, '.mim');
                const promptCountByType:{[type:string]:number} = {};
                const prompts:any[] = json.prompts;
                for (let i = 0, len = prompts.length; i < len; ++i) {
                    const prompt = prompts[i];
                    let promptType:string = prompt.prompt_sub_category;
                    const hasIndex = CATEGORY_HAS_INDEX[prompt.prompt_category];
                    if (hasIndex) {
                        promptType += '_' + prompt.index;
                    }
                    if (!promptCountByType[promptType]) {
                        promptCountByType[promptType] = 0;
                    }
                    const promptNum = ++promptCountByType[promptType];
                    prompt.prompt_id = `${mimName}_${SUBCATEGORY_ABBREVIATION[prompt.prompt_sub_category]}_${hasIndex ? prompt.index + '_' : ''}${promptNum < 10 ? '0' + promptNum : promptNum}`;
                }

                fs.writeFile(filename, JSON.stringify(json, null, '\t'), (err) => {
                    if (err) {
                        this.emit('error', `Error writing file ${filename}: ` + err.message);
                        return resolve();
                    }
                    if (this.verbose) {
                        this.emit('log', `Processed ${filename}`);
                    }
                    resolve();
                });
            });
        });
    }
}
