/**
 * @fileOverview
 * Asset Nodes extend the Node class to include information necessary to play animations and sounds
 * alongside TTS
 *
 * Created on 5/11/16.
 * @author Tom Donahue <tom.donahue@jibo.com>
 *
 * -- E. Woudenberg trimmed this down for use in jibo-dev by removing the Jibo reference (which would be circular).
 */

import Node from 'jibo-node-xml';
import { AttType } from 'jibo-node-xml';


/**
 * @description Enum of types of Asset nodes
 */
export enum AssetNodeType {
  ES = "ES",
  ANIM = "ANIM",
  SSA = "SSA",
  SFX = "SFX",
  AUDIO = "AUDIO",
}


/**
 * @description Enum of types of Asset requests
 */
export enum RequestType {
  NAME = "NAME",
  PATH = "PATH",
  QUERY = "QUERY",
  UNKNOWN = "UNKNOWN",
}


/**
 * @description Interface of RequestInfo
 * @property type {RequestType} - Type of Asset request
 * @property description {string} - Description of the Asset request
 */
export interface RequestInfo {
  type: RequestType;
  description: string;
}


/**
 * @description Interface of AttrFilter.
 * @property allOf {string[]} - All attributes that must all be included
 * @property someOf {string[]} - All attributes that at least one must be included
 * @property noneOf {string[]} - All attributes that must not be included
 * @property addAll {string[]} - All attributes that should be added (only relevant to layers= attribute)
 */
export interface AttrFilter {
  allOf: string[];
  someOf: string[];
  noneOf: string[];
  addAll: string[];
}


/**
 * @description Interface of MetaLayerPresence.
 * @property [Body] {boolean} Whether or not an animation has the Body meta layer
 * @property [Screen] {boolean} Whether or not an animation has the Screen meta layer
 * @property [Audio] {boolean} Whether or not an animation has the Audio meta layer
 */
export interface MetaLayerPresence {
  Body?: boolean;
  Screen?: boolean;
  Audio?: boolean;
}


export const MetaLayerMap = {
  body: 'Body',
  screen: 'Screen',
  audio: 'Audio'
};


const ESAliasToFilter = {
  ANIM: '!ssa-only, !sfx-only',
  SSA: 'ssa-only',
  SFX: 'sfx-only'
};


const ALL_LAYERS = 'all';


export class AssetNode extends Node {

  requestInfo: RequestInfo;
  categoryFilter: AttrFilter;
  metaFilter: AttrFilter;
  layers: MetaLayerPresence;
  layersToAdd: MetaLayerPresence;

  /**
   * Takes Node (XML) attributes and creates a RequestInfo object from them
   *
   * @param {Map<string, AttType>} att - Map of attributes to their data
   * @returns {RequestInfo}
   */
  static getRequestInfo(att: Map<string, AttType>): RequestInfo {
    let info: RequestInfo = {
      type: RequestType.UNKNOWN,
      description: RequestType.UNKNOWN
    };

    if (att.has('name')) {
      info.type = RequestType.NAME;
      info.description = `${info.type}[ ${att.get('name')} ]`;
    } else if (att.has('cat') || att.has('cats') || att.has('filter') || att.has('filters') || att.has('meta') || att.has('metas')) {
      info.type = RequestType.QUERY;
      const cat = `CAT[ ${att.get('cat') || att.get('cats')} ]`;
      const meta = `META[ ${att.get('filter') || att.get('filters') || att.get('meta') || att.get('metas')} ]`;
      info.description = `${info.type}[ ${cat} ${meta} ]`;
    } else if (att.has('path')) {
      info.type = RequestType.PATH;
      info.description = `${info.type}[ ${att.get('path')} ]`;
    }

    return info;
  }

  /**
   * Takes a comma separated string of filtering categories and modifies the provided
   * categories list with the categories we want filtered at runtime
   *
   * @param {AttType} requestedCategoriesIntent - comma separated string of requested Layers
   * @param {AttrFilter} categoryFilter - categories we want to be filtered at runtime (if any)
   */
  static addCategories(reqestedCategoriesIntent: AttType, categoryFilter: AttrFilter): void {
    AssetNode.addFilterAttributes(reqestedCategoriesIntent, categoryFilter);
  }

  /**
   * Takes a comma separated string of filtering attributes and modifies the provided
   * MetaFilter object with the list of attributes we want filtered at runtime (may contain dupes)
   *
   * @param {string} filterAttr - comma separated string
   * @param {MetaFilter} metaFilter - meta terms we want filtered at runtime (if any)
   */
  static addFilterAttributes(filterAttr: AttType, metaFilter: AttrFilter): void {
    if (filterAttr) {
      // Split on commas or semi-colons, as long as they aren't inside parens
      const terms = (filterAttr as string).split(/[;,](?![^(]*\))/g);
      terms.forEach(term => {
        const [op, attrs] = AssetNode.parseTerm(term);
        if (attrs.length > 0) {
          if (!op || op === '&') {
            metaFilter.allOf.push(...attrs);
          } else if (op === '?') {
            metaFilter.someOf.push(...attrs);
          } else if (op === '!') {
            metaFilter.noneOf.push(...attrs);
          } else if (op === '+') {
            metaFilter.addAll.push(...attrs);
          }
        }
      });
    }
  }

  /**
   * Parses a term within a query and returns the constituent parts
   *
   * @param {string} term - Individual part of a larger query
   * @returns {[string, string[]]} - Parsed term containing OP and ATTRS
   */
  static parseTerm(term: string): [string, string[]] {
    const trimmed = term.trim().toLowerCase();
    let op: string;
    let attrs: string[] = [];

    // Check if term is of the form "OP(1, 2, 3)"
    const groupedMatches = /^([!\?\+&]?)\(([\w\s-,;]+)\)/.exec(trimmed);
    if (groupedMatches) {
      op = groupedMatches[1];  // Pull out the matched operator (&, ?, !, +)
      const subterms = groupedMatches[2].split(',');  // Pull out the term list
      attrs.push(...subterms.map(subterm => subterm.trim()));
    } else {
      // Otherwise check if term is of the form "OP1"
      const indMatches = /^([!\?\+&]?)([\w-]+)/.exec(trimmed);
      if (indMatches) {
        op = indMatches[1];  // Pull out the matched operator (&, ?, !, +)
        attrs.push(indMatches[2]);  // Pull out the term
      } else {
        console.warn('ESML Asset Query contains un-parseable elements. No or unexpected results likely.');
      }
    }

    return [op, attrs];
  }

  /**
   * Takes a comma separated string of filtering requested meta terms and modifies the provided
   * MetaFilter object with the unified set of meta we want filtered at runtime
   *
   * @param {string} reqFiltered - comma separated string of requested Meta
   * @param {MetaFilter} metaFilter - meta terms we want filtered at runtime (if any)
   */
  static addMeta(reqFiltered: AttType, metaFilter: AttrFilter): void  {
    AssetNode.addFilterAttributes(reqFiltered, metaFilter);
    if (metaFilter.allOf.length > 0) {
      metaFilter.allOf = Array.from(new Set(metaFilter.allOf));
    }
    if (metaFilter.someOf.length > 0) {
      metaFilter.someOf = Array.from(new Set(metaFilter.someOf));
    }
    if (metaFilter.noneOf.length > 0) {
      metaFilter.noneOf = Array.from(new Set(metaFilter.noneOf));
    }
  }

  /**
   * Takes a comma separated string of filtering requested layers terms and modifies the provided
   * two MetaLayerPresence objects describing which sets of layers we will add/subtract at runtime
   *
   * @param {AttType} requestedLayersIntent - comma separated string of requested Layers
   * @param {MetaLayerPresence} layers - layers we want to be filtered at runtime (if any)
   * @param {MetaLayerPresence} layersToAdd - layers we want to be added at runtime (if any)
   */
  static addLayers(reqestedLayersIntent: AttType, layers: MetaLayerPresence, layersToAdd: MetaLayerPresence): void {

    let layerFilter = {
      allOf: [],
      someOf: [],
      noneOf: [],
      addAll: []
    };
    AssetNode.addFilterAttributes(reqestedLayersIntent, layerFilter);

    if (layerFilter.addAll.length > 0) {
      if (layerFilter.allOf.length > 0 || layerFilter.noneOf.length > 0) {
        throw new Error('Cannot both add layers and filter inclusively or exclusively at the same time.' +
          ' Modify layers filter to be one approach or the other.');
      }
      if (layerFilter.addAll.length === 1 && layerFilter.addAll[0] === ALL_LAYERS) {
        layers.Body = true;
        layers.Screen = true;
        layers.Audio = true;

        layersToAdd.Body = true;
        layersToAdd.Screen = true;
        layersToAdd.Audio = true;
      } else {
        layerFilter.addAll.forEach( layer => {
          const metaLayerName = MetaLayerMap[layer];
          if (metaLayerName === undefined) {
            throw new Error(`Layer ${layer} is not a valid layers filter.`);
          } else {
            layers[metaLayerName] = true;
            layersToAdd[metaLayerName] = true;
          }
        });
      }
    } else {
      if (layerFilter.allOf.length > 0 && layerFilter.noneOf.length > 0) {
        throw new Error('Cannot filter layers in both an inclusive and exclusive manner at the same time.' +
          ' Modify layers filter to be one or the other.');
      }
      if (layerFilter.allOf.length > 0) {
        layers.Body = false;
        layers.Screen = false;
        layers.Audio = false;

        layerFilter.allOf.forEach( layer => {
          const metaLayerName = MetaLayerMap[layer];
          if (metaLayerName === undefined) {
            throw new Error(`Layer ${layer} is not a valid layers filter.`);
          } else {
            layers[metaLayerName] = true;
          }
        });
      } else {
        layerFilter.noneOf.forEach( layer => {
          const metaLayerName = MetaLayerMap[layer];
          if (metaLayerName === undefined) {
            throw new Error(`Layer ${layer} is not a valid layers filter.`);
          } else {
            layers[metaLayerName] = false;
          }
        });
      }
    }
  }

  constructor(type: string, att?: Map<string, AttType>) {
    super(type);

    let defaultFilterIntent;
    if (type !== AssetNodeType.AUDIO) {
      this.type = AssetNodeType.ES;
      defaultFilterIntent = ESAliasToFilter[type];
      this.metaFilter = {
        allOf: [],
        someOf: [],
        noneOf: [],
        addAll: []
      };
      this.categoryFilter = {
        allOf: [],
        someOf: [],
        noneOf: [],
        addAll: []
      };
      AssetNode.addFilterAttributes(defaultFilterIntent, this.metaFilter);
    }

    if (att) {
      this.att = att;
      this.requestInfo = AssetNode.getRequestInfo(att);

      // Handle any categories
      const requestedCategoryIntent = this.att.get('cat') || this.att.get('cats');
      if (requestedCategoryIntent) {
        AssetNode.addCategories(requestedCategoryIntent, this.categoryFilter);
      }

      // Handle any metas
      const requestedFilterIntent = this.att.get('filter') || this.att.get('filters') || this.att.get('meta') || this.att.get('metas');
      if (requestedFilterIntent) {
        AssetNode.addMeta(requestedFilterIntent, this.metaFilter);
      }

      // Handle any layers
      this.layers = {};
      this.layersToAdd = {};
      const reqLayers = this.att.get('layers') || this.att.get('layer');
      if (reqLayers) {
        AssetNode.addLayers(reqLayers, this.layers, this.layersToAdd);
      }
    }
  }
}
