import fs = require('fs');
import path = require('path');
import minimist = require('minimist');
import mkdirp = require('mkdirp');
import glob = require('glob');
import Behaviorify from './Behaviorify';
import Flowify from "./Flowify";
import chalk = require('chalk');

export default function cli() {

    const args:any = minimist(process.argv.slice(2), {
        string: ['input', 'output'],
        boolean: ['verbose', 'update'],
        alias: {
            v: 'verbose',
            u: 'update',
            i: 'input',
            o: 'output'
        },
        default: {
            verbose: false,
            update: false
        }
    });

    let files = args._;

    if (args.input) {
        files = glob.sync(path.join(args.input, '**/*.{bt,flow}'));
    }
    if (!files.length) {
        console.error(chalk.red("Must provide files to process"));
        process.exit(0);
    }

    //get the path relative to the behaviors root
    files.forEach((file, i) => {
        files[i] = path.relative(args.input, file);
    });

    // Convert a file
    if (args.update && files.length > 1) {
        files.forEach(function(filename){
            const uri = path.resolve(filename);
            const data = JSON.parse(fs.readFileSync(uri, 'utf8'));
            const format = new Behaviorify(filename, data);
            fs.writeFileSync(uri, JSON.stringify(format.data, null, "  "));
            if (args.verbose) {
                console.log(chalk.green(" -> Updated %s"), filename);
            }
        });
        process.exit(0);
    }

    // Convert a file
    else if (files.length) {

        // Make directory in case
        if (args.output) {
            mkdirp.sync(path.resolve(args.output));
        }

        files.forEach(function(filename){

            let parts = filename.split('.');
            let extension = '.' + parts[parts.length-1];

            if (extension !== '.bt' && extension !== '.flow') {
                console.error(chalk.red("Invalid: not a *.bt or *.flow file: %s"), filename);
                return;
            }
            const uri = path.resolve(args.input, filename);
            const data = JSON.parse(fs.readFileSync(uri, 'utf8'));

            // Make sure the file is valid
            try {
                fs.statSync(uri);
            }
            catch (e) {
                console.error(chalk.red("File does not exist '%s'", filename));
                return;
            }

            let format:Behaviorify;
            switch (extension) {
                case '.flow':
                    format = new Flowify(filename, data);
                    break;
                case '.bt':
                    format = new Behaviorify(filename, data);
                    break;
            }

            if (args.output) {
                let outputName;

                // Rebase to the input folder
                if (args.input) {
                    outputName = filename.replace(RegExp('\\' + extension + '$'), '.js')
                        .replace(args.input + '/', '');
                }
                else {
                    outputName = path.basename(filename, extension) + '.js';
                }

                const outputFile = path.join(args.output, outputName);
                const outputDir = path.dirname(outputFile);

                // Make the output directory
                mkdirp.sync(outputDir);

                fs.writeFileSync(outputFile, format.exec());
                if (args.verbose) {
                    console.log(chalk.green("Saved '%s' to '%s'"), filename, outputName);
                }
            }
            else {
                console.log(format.exec());
            }
        });
        process.exit(0);
    }

    console.error(chalk.red("Invalid command."));
    process.exit(1);
}
