import JiboDev from '../JiboDev';
import AnimRefChecker from '../../anim-ref/anim-ref-checker';
import chalk = require('chalk');

export default function(gulp, dev:JiboDev) {
    gulp.task('anims', function(done){
        const result = AnimRefChecker.exec({skill:'.', verbose:dev.args.verbose});
        result.on('log', (message) => {
            console.log(chalk.green(message));
        });
        result.on('warn', (message) => {
            console.log(chalk.yellow(message));
        });
        result.on('lintError', (err) => {
            console.error(chalk.red(err));
        });
        result.on('end', (err) => {
            done();
        });
    });
}