import chalk = require('chalk');
import gulp = require('gulp');
import path = require('path');
import tasks = require('./tasks');
import prettyTime = require('pretty-hrtime');
import minimist = require('minimist');

/**
 * The config options
 * @interface JiboDev~JiboDevConfig
 */
export interface JiboDevConfig {
    /**
     * The name of the package. THis is required if `standalone` is true
     * @name JiboDev~JiboDevConfig#name
     * @type {String}
     * @default <package name>
     */
    name?:string;

    /**
     * If the package should be bundled with Browserify's standalone option.
     * @name JiboDev~JiboDevConfig#standalone
     * @type {String}
     * @default false
     */
    standalone?:boolean;

    /**
     * The folder to watch
     * @name JiboDev~JiboDevConfig#watch
     * @type {String}
     * @default src
     */
    watch?:string;

    /**
     * Entry point for the application
     * @name JiboDev~JiboDevConfig#app
     * @type {String}
     * @default src/index.ts
     */
    app?:string;

    /**
     * The output file name
     * @name JiboDev~JiboDevConfig#bundle
     * @type {String}
     * @default index.js
     */
    bundle?:string;

    /**
     * The name of the map file
     * @name JiboDev~JiboDevConfig#map
     * @type {String}
     * @default index.js.map
     */
    map?:string;

    /**
     * The folder to watch
     * @name JiboDev~JiboDevConfig#watch
     * @type {String}
     * @default tslint.json
     */
    tslint?:string;

    /**
     * Additional files to clean
     * @name JiboDev~JiboDevConfig#clean
     * @type {Array<String>}
     * @default []
     */
    clean?:string[];

    /**
     * Output folder for rules
     * @name JiboDev~JiboDevConfig#rules
     * @type {Array<String>}
     * @default rules
     */
    rules?:string;

    /**
     * Input folder for rules
     * @name JiboDev~JiboDevConfig#rulesSrc
     * @type {Array<String>}
     * @default src/rules
     */
    rulesSrc?:string;

    /**
     * Input folder for flow
     * @name JiboDev~JiboDevConfig#flowsSrc
     * @type {Array<String>}
     * @default src/flows
     */
    flowsSrc?:string;
}

export interface JiboDevArgs {
    production:boolean;
    prod:boolean;
    verbose:boolean;
}

/**
 * Provide the build process for skills.
 * @class JiboDev
 */
class JiboDev {

    public dirname:string;
    public config:JiboDevConfig;
    public args:JiboDevArgs;

    /**
     * Command line invokation of the jibo-dev build tools
     * @method JiboDev.cli
     */
    public static cli(): void {
        const task:string = process.argv[2] || 'build';
        if (!task || !tasks[task]) {
            console.log(chalk.red('Must provide a valid task (build, clean, watch)'));
            return process.exit(1);
        }
        const dev:JiboDev = new JiboDev();
        dev.run(task)
            .then(() => {
                process.exit(0);
            })
            .catch(err => {
                console.log(chalk.red(err));
                process.exit(1);
            });
    }

    /**
     * @constructor
     * @param {String} [dirname] The directory name to run tasks
     * @param {JiboDev~JiboDevConfig} [config] Optional configuration
     */
    constructor(dirname?:string, config?:JiboDevConfig) {

        /**
         * Path to the directory of skill
         * @name JiboDev#dirname
         * @type {JiboDev~JiboDevConfig}
         */
        this.dirname = dirname || process.cwd();

        /**
         * The package.json of the skill.
         * @name JiboDev#packageInfo
         * @type {Object}
         */
        const packageInfo = require(path.resolve(this.dirname, 'package.json'));
        // Check for the command
        if (!config) {
            config = packageInfo.config as JiboDevConfig;
        }

        /**
         * The configuration
         * @name JiboDev#config
         * @type {JiboDev~JiboDevConfig}
         */
        this.config = Object.assign({
            name: packageInfo.name,
            standalone: false,
            app: 'src/index.ts',
            bundle: 'index.js',
            map: 'index.js.map',
            tslint: 'tslint.json',
            watch: 'src',
            rules: 'rules',
            rulesSrc: path.join('src', 'rules'),
            flowsSrc: path.join('src', 'flows'),
            clean: []
        }, config || {});

        // Support clean as a glob
        if (typeof this.config.clean === "string") {
            this.config.clean = [this.config.clean];
        }

        /**
         * Commandline arguments
         * @name JiboDev#args
         * @type {Object}
         */
        this.args = (minimist(process.argv.slice(2), {
            boolean: [
                'production',
                'verbose'
            ],
            alias: {
                prod: 'production'
            },
            default: {
                production: false,
                verbose: false
            }
        }) as any);

        // Manually add the built-in tasks first
        for(const name in tasks) {
            tasks[name](gulp, this);
        }

        gulp.on('task_start', function(e) {
            console.log('Starting', '\'' + chalk.cyan(e.task) + '\'...');
        });

        gulp.on('task_stop', function(e) {
            const time = prettyTime(e.hrDuration);
            console.log(
              'Finished', '\'' + chalk.cyan(e.task) + '\'',
              'after', chalk.magenta(time)
            );
        });

        gulp.on('task_err', function(e) {
            const time = prettyTime(e.hrDuration);
            console.log(
              '\'' + chalk.cyan(e.task) + '\'' + ' ' +
              chalk.red('errored after'),
              chalk.magenta(time)
            );
        });

        gulp.on('task_not_found', function(err) {
            console.log(
              chalk.red('Task \'' + err.task + '\' is not in your gulpfile')
            );
            console.log('Please check the documentation for proper gulpfile formatting');
            process.exit(1);
        });
    }

    /**
     * Run as ask command.
     * @method JiboDev#run
     * @param {String} [task='build'] Name of the task: build, clean, watch
     * @return Promise<void> The promise when complete.
     */
    public run(task:string): Promise<void> {
        return new Promise<void>((resolve, reject) => {
            gulp.start(task, (err) => {

                // When watching do nothing
                if (task === 'watch'){
                    if (err) {
                        console.log(chalk.red(err.message));
                    }
                    return;
                }

                // Return result of the task
                if (err) {
                    reject(err);
                }
                else {
                    resolve();
                }
            });
        });
    }
}

export default JiboDev;
