import minimist = require('minimist');
import chalk = require('chalk');
import { KeysRefChecker } from './keys-ref-checker';

function usage() {
    console.log(`
usage: node keys-ref-checker.js [options] /path/to/skill

This program checks all the .keys files within a skill to determine if any of the assets it references are missing.

  options:
    -a --animdb /path/to/animdb.json ; default is to use the skill's node_modules/jibo-anim-db-animations DB;
    -u --skip-underscores ; ignore all directories with a leading underscore .
    -v --verbose ; print details as files are checked.
    -F --fix-nonunique-layers ; find any duplicate layerIDs across the animations and create a new unique ID for them.
    --no-report ; don't generate a reference check report.
`);
    process.exit(0);
}

export default function cli() {
    const argv = process.argv.slice(2);
    if (argv.length === 0) {
        usage();
    }
    const args:any = minimist(argv, {
        string: ['skill', 'animdb'],
        boolean: ['verbose', 'no-report','skip-underscores', 'fix-nonunique-layers'],
        alias: {
            'check-skill': 'skill',
            s: 'skill',
            a: 'animdb',
            v: 'verbose',
            u: 'skip-underscores',
            F: 'fix-nonunique-layers',
            R: 'no-report'
        },
        default: {
            verbose: false,
            'no-report': false,
            'fix-nonunique-layers': false,
            'skip-underscores': false
        }
    });

    args.skill = args.skill || args._[0];

    if (!args.skill) {
        console.log(chalk.red('Error: a skill directory must be specified.'));
        usage();
    }

    const result = KeysRefChecker.exec(args);

    console.log('Checking Keys references...');

    result.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        console.log('Done!');
        process.exit(0);
    });

    result.on('status', (message) => {
        console.log(message);
    });
    
    result.on('log', (message) => {
        if (args.verbose) {
            console.log(chalk.green(message));
        }
    });

    result.on('lintError', (err) => {
        console.error(chalk.red(err));
    });
}