import Activity from "../flow-objects/Activity";
import Procedure from "../flow-objects/Procedure";
import Transition from "../flow-objects/Transition";

const fs = require('fs');

/**
 * A minimal Flow File loader used by Behaviorify for parsing a .flow file's JSON into
 * the Flow primary objects (Procedures, Activities and Transitions).
 */
class GojsBareBonesLoader {
    public static getName(uri:string):string {
        // Remove directory path
        let names = uri.split('/');
        // Remove extension
        let name = names[names.length-1].replace(/\.[^.]*$/, '');
        return name;
    }

    public static getBase(uri:string):string {
        // Remove filename part from directory path.
        return uri.replace(/\/[^/]*$/, '');
    }

    public static loadProcedureRelative(currentUri:string, name:string) {
        let baseUri = GojsBareBonesLoader.getBase(currentUri);
        let uri = baseUri + '/' + name + '.flow';
        return GojsBareBonesLoader.loadProcedure(uri);
    }

    public static loadProcedure(uri:string):Procedure {
        let data = fs.readFileSync(uri, 'utf8');
        let base = JSON.parse(data);
        return GojsBareBonesLoader.loadParsedProcedure(uri, base);
    }

    public static loadParsedProcedure(uri:string, base:any):Procedure {
        let name = GojsBareBonesLoader.getName(uri);

        let procedure = new Procedure(name, uri, {}, {});

        for (let i = 0; i < base.linkDataArray.length; i++) {
            let goLink = base.linkDataArray[i];
            let transitionValue = goLink.text === undefined ? "" : goLink.text;
            let transition = new Transition(goLink.from, goLink.to, transitionValue);
            procedure.add_transition(transition);
        }

        for (let i = 0; i < base.nodeDataArray.length; i++) {
            let goNode = base.nodeDataArray[i];
            let activity = new Activity(goNode.name, goNode.id, goNode.class, goNode['asset-pack'], goNode.options);
            procedure.add_activity(activity);
        }

        return procedure;
    }
}

export default GojsBareBonesLoader;