import minimist = require('minimist');
import chalk = require('chalk');
import { KeysCompiler } from './KeysCompiler';

function usage() {
    console.log(`
usage: node bin/keys-compiler.js [options] /path/to/skill

This program compiles all the .keys files within a skill into .anim and .assets files.

  options:
    -a --animdb /path/to/animdb.json ; default is to use the skill's node_modules/jibo-anim-db-animations DB 
    -u --skip-underscores ; skip files and dirs with leading _ (underscore).
    --file <file to process> ; instead of using the given directory, process the given files.
`);
    process.exit(0);
}

export default function cli() {
    const argv = process.argv.slice(2);
    if (argv.length === 0) {
        usage();
    }
    const args:any = minimist(argv, {
        string: ['animdb', 'file'],
        boolean: ['verbose', 'skip-underscores'],
        alias: {
            u: 'skip-underscores',
            a: 'animdb',
            v: 'verbose'
        },
        default: {
            verbose: false
        }
    });

    args.skill = args.skill || args._[0];

    if (!args.skill) {
        console.log(chalk.red('Error: a skill directory must be specified.'));
        usage();
    }

    const result = KeysCompiler.exec(args);

    result.on('end', (err) => {
        if (err) {
            console.log(err);
        }
        process.exit(0);
    });

    result.on('log', (message) => {
        if (args.verbose) {
            console.log(chalk.green(message));
        }
    });

    result.on('lintError', (err) => {
        console.error(chalk.red(err));
    });
}