import path = require('path');
import browserify = require('browserify');
import gulp = require('gulp');
import {JiboDevConfig} from '../JiboDev';
import gulpif = require('gulp-if');
import buffer = require('vinyl-buffer');
import source = require('vinyl-source-stream');
import composer = require('gulp-uglify/composer');
import uglifyes = require('uglify-es');
import tsify = require('tsify-preprocess');
import mapstraction = require('mapstraction');
import watchify = require('watchify');
import transform from '../../browserify/BrowserifyTransform';
import {JiboDevArgs} from '../JiboDev';

export default function(options:JiboDevConfig, args:JiboDevArgs, watch?:boolean) {
    return function(done:Function) {
        const prod = args.production;
        const bundler = browserify({
            entries: options.app,
            bundleExternal: false,
            debug: !prod,
            builtins: false,
            extensions: ['.bt', '.flow'],
            cache: {},
            packageCache: {},
            standalone: options.standalone ? options.name : undefined
        });

        // TypeScript options
        bundler.plugin(tsify, {
            removeComments: true,
            target: 'es6',
            preprocess: {
                DEBUG: !prod,
                RELEASE: !!prod,
                PARTNER: !!process.env.PARTNER,
                INTERNAL: !process.env.PARTNER,
            }
        });

        // Install the source-map extractor
        // when build in debug mode
        if (!prod) {
            bundler.plugin(mapstraction, {
                _: [options.map]
            });
        }

        // Install the watch
        if (watch) {
            //as watch will check against many files, we will create our RegExp once
            const regexp = new RegExp('^' + path.resolve(options.watch));
            bundler.plugin(watchify, {
                ignoreWatch: [function(path) {
                    //only watch things in the watch folder, because that's what the option is there for
                    return !regexp.test(path);
                }],
                poll: true
            });
        }

        // Add the transform for bt and flow files
        bundler.transform(transform);

        // See https://www.npmjs.com/package/gulp-uglify#using-a-different-uglifyjs
        const uglify = composer(uglifyes, console);

        // Setup for watching
        function rebundle() {
            const bundle = bundler.bundle()
                .on('error', done)
                .pipe(source(options.bundle))
                .pipe(buffer())
                .pipe(gulpif(prod, uglify()))
                .pipe(gulp.dest('.'));
            if (!watch) {
                bundle.on('end', done);
            }
            return bundle;
        }
        bundler.on('update', rebundle);
        bundler.on('log', console.log.bind(console));
        rebundle();
    };
}
