import JiboDev from '../JiboDev';

export default function(gulp, dev:JiboDev) {
    gulp.task('watch', ['watch-build'], function() {
        gulp.watch(dev.config.watch, ['lint']);
        gulp.watch(dev.config.flowsSrc + "**/*.flow", ['flows']);
        gulp.watch(dev.config.rulesSrc + "**/*.rule", ['rules']);
    });
}