import fs = require('fs');
import path = require('path');
import cli from './cli';
import vm = require('vm');
import {EventEmitter} from 'events';
import glob = require('glob');
import { Parser } from 'jibo-node-xml';
import Node from 'jibo-node-xml';
import { api, AnimQuery } from 'jibo-anim-db';
import { loaders } from 'jibo-flow-core';
import request = require('request');
import { AssetNode } from './AssetNode';
import {DateTime, Location} from 'jibo-data-utils';
const resolve = require('resolve');

/**
 * Statically check a skill for local animation and AnimDB reference errors.
 * ```
 * import {AnimRefCheck} from 'jibo-dev';
 * ```
 * @class AnimRefChecker
 * @param {string} projectRoot Path to the skill's project-level directory.
 */
// Class that checks a skill's animation references against an animation DB.

interface Ref {
    type: string;
    location: string;
    path?: string;
    attr: any;
    att: Map<string, any>;
    name?: string;
    params?: AnimQuery;
}

export class AnimRefChecker extends EventEmitter {
    public verbose: boolean;
    private refs: Ref[] = [];
    private errors: Error[] = [];
    private noManifest: boolean;
    private noReport: boolean;
    private manifest: string;
    private skillDir: string;
    private animdb: string;
    private animDBPresent: boolean = false;

    /**
     * Command-line tool for validating a skill against the Animation DB.
     * @method AnimRefChecker.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    /**
     * Command-line tool entrypoint for validating the AnimDB references in a skill.
     * @method AnimRefChecker.exec
     * @param {any} args Options for controlling the checker.
     * @return {EventEmitter} Emits 'lintError', 'end' and 'log' event
     */
    static exec(args): EventEmitter {
        const refChecker = new AnimRefChecker(args);
        refChecker.run();
        return refChecker;
    }

    constructor(public args: any) {
        super();
        this.noManifest = args['no-manifest'];
        this.noReport = args['no-report'];
        this.manifest = args.manifest;
        this.skillDir = args.skill;
        this.animdb = args.animdb;
        this.verbose = args.verbose;
    }

    /**
     * Main entry point for execution. This loads the required files and proceeds through all the checks.
     * @method AnimRefChecker.run
     */
    public run(): void {

        // Init animation DB
        this.init().then(() => {
            this.animDBPresent = true;
        }).catch((err) => {
            if (err.path && err.path.endsWith('node_modules/jibo-anim-db-animations/animdb.json')) {
                console.log('Skill has no animation database -- animDB references will not be checked.');
            } else {
                console.log('Failed to initialize animation database -- animDB references will not be checked', err);
            }
        }).then(() => {
            this.doChecks();
        });
    }

    public doChecks() {
        if (this.manifest) {
            this.loadRefsFromManifest(() => this.runChecks());
        } else {
            this.loadRefsFromSkill(() => this.runChecks());
        }
    }

    /**
     * Write discovered errors to the given file.
     * @method AnimRefChecker#writeReportToFile
     * @param {string} filename
     */
    public writeReportToFile(filename: string, title: string): void {
        const report = this.getErrorReport();
        fs.writeFileSync(filename, `AnimDB Reference Report for ${title}\n` + report);
    }

    /**
     * Format all the discovered errors into a report.
     * @method AnimRefChecker#getErrorReport
     * @returns {string} Report of all discovered errors.
     */
    public getErrorReport(): string {
        let report = '';
        let location = '';
        // Group all the errors in the same file/activity together
        this.errors.sort((a: Error, b: Error) => a.location.localeCompare(b.location));
        for (const error of this.errors) {
            if (error.location !== location) {
                report += `\nErrors found in '${error.location}':\n`;
                location = error.location;
            }
            report += `${error}\n`;
        }
        return report;
    }

    // Convert possible asset-pack style reference into full path

    public resolveAssetPath(src: string, middle?: string) {
        let parts = src.split('://');
        middle = middle || '';
        if (parts.length > 1) {
            let dir = this.resolve(parts[0]);
            return path.resolve(dir, middle, parts[1]);
        } else {
            return path.resolve(this.skillDir, middle, src);
        }
    }

    private runChecks() {
        if (!this.noReport) {
            this.checkRefs();
        }
        if (this.skillDir && !this.noManifest) {
            this.createManifest();
        }
        const report = this.getErrorReport();
        if (report) {
            this.emit('lintError', report);
        }
        this.emit('end');
    }

    private resolve(wanted) {
        let dir;
        try {
            dir = resolve.sync(wanted, {basedir: this.skillDir});
            dir = path.dirname(dir);
        } catch (e) {
            console.log(`Could not resolve module named ${wanted}`);
        }
        return dir;
    }

    // Load the optional animdb if provided, otherwise the skill's installed animation DB.

    private async init(): Promise<void> {
        let animDBpath = this.animdb;
        if (!animDBpath) {
            let adaPath = this.resolve('jibo-anim-db-animations');
            animDBpath = adaPath && path.resolve(adaPath, 'animdb.json');
        }
        return api.init(null, animDBpath);
    }

    // Create Maps (needed by AssetNode) from the attr object stored in the JSON file.
    private fixupManifest(refs:any) {
        for (let ref of refs) {
            ref.att = new Map<string, string>();
            for (let key in ref.attr || {}) {
                ref.att.set(key, ref.attr[key]);
            }
        }
    }

    private loadRefsFromManifest(cb) {
        if (this.manifest.startsWith('http://') || this.manifest.startsWith('https://')) {
            const url4raw = this.manifest; // .replace('/blob/', '/raw/'); -- won't work unless you supply the user's credentials
            request(url4raw, (error, response, body) => {
                if (error) {
                    return this.emit('end', `Failure loading HTML file ${url4raw}`);
                }
                try {
                    this.refs = JSON.parse(body);
                    this.fixupManifest(this.refs);
                } catch (e) {
                    return this.emit('end', `Could not parse contents of ${url4raw} -- did you give a URL for the raw file?`);
                }
                cb();
            });

        } else {
            fs.readFile(this.manifest, 'utf8', (error, data) => {
                if (error) {
                    return this.emit('end', `${error}`);
                }
                this.refs = JSON.parse(data);
                this.fixupManifest(this.refs);
                cb();
            });
        }
    }

    private loadRefsFromSkill(cb) {
        for (const checker of [
            new FlowChecker(this, this.skillDir),
            new BtChecker(this, this.skillDir),
            new MimChecker(this, this.skillDir)]) {
            checker.extractRefsFromFiles();
            this.refs = this.refs.concat(checker.getReferences());
        }
        cb();
    }

    private checkRefs() {
        for (const ref of this.refs) {
            this.checkRef(ref);
        }
    }

    // Check a ref against the DB
    private checkRef(ref: Ref): boolean {
        let fail = false;
        switch (ref.type) {
            // Handle Markup-based references
            case 'SSA':
            case 'SFX':
            case 'ES':
            case 'ANIM':
                if (!this.animDBPresent) {
                    break;
                }
                if (ref.attr.name) { // Handle name references
                    const anim = api.getAnimByName(ref.attr.name);
                    if (!anim) {
                        this.addError(ref.location, `Animation DB found no animation for TTS markup <${ref.type} name="${ref.attr.name}"/>`, 'BAD-ANIM-NAME');
                        fail = true;
                    }
                } else {
                    const animQuery = formQuery(ref);
                    const result = api.query(animQuery);
                    if (result.matching.length === 0) {
                        this.addError(ref.location, `Animation DB found no matches for TTS markup <${ref.type} ${this.xmlify(ref.attr)}/> query: ${JSON.stringify(animQuery)}`, 'ANIM-QUERY-FAIL');
                        fail = true;
                    }

                }
                break;
            case 'animRefByName':
                if (!this.animDBPresent) {
                    break;
                }
                const anim = api.getAnimByName(ref.name);
                if (!anim) {
                    this.addError(ref.location, `Animation name "${ref.name}" not found in animation DB`, 'BAD-ANIM-NAME');
                    fail = true;
                }
                break;
            case 'animRefByQuery':
                if (!this.animDBPresent) {
                    break;
                }
                const querytmp = JSON.parse(JSON.stringify(ref.params));
                const result = api.query(querytmp);
                if (result.matching.length === 0) {
                    this.addError(ref.location, `Animation DB found no matches for query params "${JSON.stringify(ref.params)}.`, 'ANIM-QUERY-FAIL');
                    fail = true;
                }
                break;
            case 'animRefByPath':
                let keysfile = this.resolveAssetPath(ref.path, 'animations');
                if (!fs.existsSync(keysfile)) {
                    this.addError(ref.location, `No animation found at ${keysfile}`, 'BAD-ANIM-PATH');
                    fail = true;
                }
                break;
        }
        return fail;
    }

    private xmlify(attr) {
        let xattr = '';
        for (const key in attr) {
            xattr += `${key}="${attr[key]}" `;
        }
        return xattr;
    }

    private createManifest() {
        const filename = path.join(this.skillDir, 'animdb-manifest.json');
        fs.writeFileSync(filename, JSON.stringify(this.refs, null, '  '), 'utf8');
    }

    /**
     * Accumulate an error referring to an activity.
     * @method AnimRefChecker#addProcedureError
     * @private
     * @param {Activity} activity
     * @param {string} message
     * @param {string} code
     */
    private addError(location: any, message: string, code: string) {
        this.errors.push(new Error(location, message, code));
    }
}


enum animSelector {path = 1, pathFunction = 2, name = 3, query = 4}

class BehaviorChecker {
    public dir: string;
    public verbose: boolean;
    private errors: Error[];
    private refs: any[];

    constructor(public refChecker, dir) {
        this.dir = path.resolve(dir);
        this.errors = [];
        this.refs = [];
        this.verbose = refChecker.verbose;
    }

    public getReferences() {
        return this.refs;
    }

    public extractRefsFromOptions(uri, activities) {
        for (const id in activities) {
            const activity = activities[id];
            // TODO: location to be used (later) in preflight to allow the user to navigate directly to the error.
            let localPath = uri.substr(this.dir.length+1);
            const location = `${localPath} - ${id}`;
            switch (activity.class) {
                case 'PlayAnimation':
                    switch (activity.options && activity.options.animSelector) {
                        case animSelector.name:
                            this.refs.push({type: 'animRefByName', location, name: activity.options.animName});
                            break;
                        case animSelector.query:
                            this.refs.push({
                                type: 'animRefByQuery',
                                location,
                                params: this.getQueryParams(activity.options.queryParams)
                            });
                            break;
                        case animSelector.path:
                            this.refs.push({
                                type:'animRefByPath',
                                location,
                                path: activity.options.animPath
                            });
                    }
                    break;
                case 'TextToSpeech':
                    const refs = getAnimReferencesFromXml(this.refChecker, location, activity.options.words);
                    this.refs = this.refs.concat(refs);
                    break;
            }
        }
    }

    // Parse the queryParams entry:
    // "queryParams": "() => ({
    //         category: 'emoji',
    //         categories: ['happy']
    //         includeMeta: ['sleep'],
    //         duration: 3,
    //         hasAudio: 'NO'
    //     });"

    getQueryParams(queryParams) {
        const ref = {};
        for (const line of queryParams.split('\n')) {
            const parts = line.split(':');
            if (parts.length === 2) {
                const key = parts[0].trim();
                let value = parts[1].trim();
                if (value.slice(-1) === ',') {
                    value = value.slice(0, -1);
                }
                if (key === 'category' || key === 'hasAudio') {
                    ref[key] = value.slice(1, -1); // handle quoted string types
                }
                if (key === 'includeMeta' ||
                    key === 'excludeMeta' ||
                    key === 'includeSomeMeta' ||
                    key === 'categories') {
                    ref[key] = JSON.parse(value.replace(/'/g, '"')); // handle array types
                }
                if (key === 'duration' || key === 'durationError') {
                    ref[key] = JSON.parse(value); // handle number types
                }
            }
        }
        return ref;
    }
}

class FlowChecker extends BehaviorChecker {
    public extractRefsFromFiles() {
        const files = glob.sync(path.join(this.dir, 'src/*' + '*/*.flow'));
        if (this.verbose && !files.length) {
            this.refChecker.emit('log', `No Flows found in ${this.dir}/src`);
        }
        for (const filename of files) {
            this.extractRefsFromFile(filename);
        }
    }

    public extractRefsFromFile(uri) {
        const loader = new loaders.GojsLoader();
        const procedure = loader.loadProcedure(uri);
        this.extractRefsFromOptions(uri, procedure.activities);
    }
}

class BtChecker extends BehaviorChecker {
    public extractRefsFromFiles() {
        //                                            vvv  <- Hack to fix jsdocs error.
        const files = glob.sync(path.join(this.dir, 'src/*' + '*/*.bt'));
        if (this.verbose && !files.length) {
            this.refChecker.emit('log', `No Behavior Trees found in ${this.dir}/src`);
        }
        for (const filename of files) {
            this.extractRefsFromFile(filename);
        }
    }

    public extractRefsFromFile(uri) {
        let bt;
        try {
            bt = JSON.parse(fs.readFileSync(uri, 'utf8'));
        } catch (e) {
            this.refChecker.addError(uri, `BT file '${uri}' could not be loaded and parsed`, 'BT-LOAD');
            return;
        }

        this.extractRefsFromOptions(uri, bt);
    }
}

class MimChecker {
    public dir: string;
    private errors: Error[];
    private refs: any[];
    private verbose: boolean;
    private variableTypes: any;

    constructor(public refChecker, dir) {
        this.dir = path.resolve(dir);
        this.errors = [];
        this.refs = [];
        this.verbose = refChecker.verbose;
        this.variableTypes = null;
    }

    public getReferences() {
        return this.refs;
    }

    public extractRefsFromFiles() {
        this.setupTypes();
        const files = glob.sync(path.join(this.dir, 'mims/*' + '*/*.mim'));
        if (this.verbose && !files.length) {
            this.refChecker.emit('log', `No mims found in ${this.dir}/mims`);
        }
        for (const filename of files) {
            this.extractRefs(filename);
        }
    }

    // Extract the animation DB references from all the mim prompts and accumulate them in this.refs
    // Also check validity of prompts and conditions

    public extractRefs(mimPath): any {
        let mim;
        try {
            mim = JSON.parse(fs.readFileSync(mimPath, 'utf8'));
        } catch (e) {
            this.refChecker.addError(mimPath, `references Mim file '${mimPath}' with bad JSON`, 'JSON-PARSE');
            return;
        }

        let localPath = mimPath.substr(this.dir.length+1);
        for (const prompt of mim.prompts) {
            const location = `${localPath} - prompt ${prompt.prompt_id}`;
            this.refs = this.refs.concat(getAnimReferencesFromXml(this.refChecker, location, prompt.prompt));
        }

        let sandbox;
        let filename;
        if (this.variableTypes) {
            filename = path.basename(mimPath);

            sandbox = {};
            this.addVariableToSandbox("_now", {"type": "datetime"}, sandbox); // _now is in every sandbox
            if ('global' in this.variableTypes) {
                for (let variable in this.variableTypes.global) {
                    this.addVariableToSandbox(variable, this.variableTypes.global[variable], sandbox);
                }
            }
            if (filename in this.variableTypes) {
                for (let variable in this.variableTypes[filename]) {
                    this.addVariableToSandbox(variable, this.variableTypes[filename][variable], sandbox);
                }
            }
            sandbox = vm.createContext(sandbox);

            for (const prompt of mim.prompts) {
                this.checkPromptValidity(filename, prompt, sandbox);
            }
        }
    }

    public setupTypes() {
      const files = glob.sync(path.join(this.dir, 'mim-types.json'));
      if (!files.length) {
          this.refChecker.emit('log', `No mim-types.json found in ${this.dir}`);
          return;
      }
      for (const filename of files) {
          this.addTypesToVariableTypes(filename);
      }
    }

    public addTypesToVariableTypes(filename) {
      if (this.variableTypes === null) {
        this.variableTypes = {};
      }

      let types;
      try {
        types = JSON.parse(fs.readFileSync(filename, 'utf8'));
      } catch (e) {
        this.refChecker.addError(filename, `references file '${filename}' with bad JSON`, 'JSON-PARSE');
        return;
      }

      for (let file in types) {
        this.variableTypes[file] = types[file];
      }
    }

    public addVariableToSandbox(variable, typeInfo, sandbox) {
      if (typeInfo.type === 'string') {
        sandbox[variable] = 'foo';
      } else if (typeInfo.type === 'number') {
        sandbox[variable] = 42;
      } else if (typeInfo.type === 'boolean') {
        sandbox[variable] = true;
      } else if (typeInfo.type === 'datetime') {
        sandbox[variable] = new DateTime();
      } else if (typeInfo.type === 'location') {
        sandbox[variable] = Location.jiboHome;
      }
    }

    public checkPromptValidity(filename, prompt, sandbox):boolean {
      if (this.variableTypes === null) {
        return true; // don't check types if there are no types to check
      }
      return this.conditionIsWellFormed(filename, prompt, sandbox) &&
             this.promptTextIsWellFormed(filename, prompt, sandbox);
    }

    public conditionIsWellFormed(filename, prompt, sandbox):boolean {
        if (!prompt.condition) {
            return true;
        }

        //zero or negative weights should be interpreted as 'never pick this prompt'
        if (prompt.weight && prompt.weight <= 0) {
            return false;
        }

        //remove the leading '${' and trailing '}' from the condition string, because
        //we don't want those - older mims may have been created with them present
        let condition = prompt.condition.replace(/^\$\{/, "").replace(/\}$/, "");
        //do a safe eval on the condition
        try {
            return !!vm.runInContext(condition, sandbox);
        } catch (e) {
            this.refChecker.addError(`error evaluating prompt condition in ${filename}: ${prompt.condition} - error: ${e.message}`);
            return false;
        }
    }

    public promptTextIsWellFormed(filename, prompt, sandbox):boolean {
      if (!prompt.prompt) {
        return true;
      }

      if (prompt.weight && prompt.weight <= 0) {
          return false;
      }

      try {
          return !!vm.runInContext("`" + prompt.prompt + "`", sandbox);
      } catch (e) {
          this.refChecker.addError(`error evaluating prompt formation in ${filename}: ${prompt.prompt} - error: ${e.message}`);
          return false;
      }
    }
}

function getAnimReferencesFromXml(refChecker, location, prompt):Ref[] {
    const xml = `<root>${prompt}</root>`;
    let node;
    try {
        node = Parser.parseXML(xml);
    } catch (e) {
        const code = 'SSML-PARSE';
        let message = `${e} - ${prompt}`;
        refChecker.addError(location, message, code);
    }
    let refs = [];
    if (node) {
        refs = getAnimReferencesFromNodes(refChecker, location, [node]);
        // debugging
        // if (refs.length !== 0) {
        //     console.log(prompt);
        //     for (let i of refs) {
        //         console.log(formQuery(i));
        //     }
        // }
    }
    return refs;
}

function getAnimReferencesFromNodes(refChecker, location, nodes:Node[]):Ref[] {
    const template = /\$\{[^\$\{]*\}/g;  // Regex looking for ${}
    let refs:Ref[] = [];
    let resolvable = true;
    for (const elem of nodes) {
        let type = `${elem.type}`.toUpperCase();
        if (['ANIM', 'TTS', 'SSA', 'SFX', 'ES'].indexOf(type) !== -1) {
            // Place both the Map and a normal JS object with the same keys and values in the reference.
            let attr = {};
            for (let key of elem.att.keys()) {
                const val = elem.att.get(key) as string;
                if (template.test(key) || template.test(val)) {  // If our nodes contain ${} in their queries
                    resolvable = false;  // Mark this ESML node as unresolvable
                }
                attr[key] = val;
            }
            if (resolvable) {
                let query: Ref = { type, location, attr, att: elem.att };
                refs.push(query);
            } else {
                refChecker.emit('warn', `ESML contains templates, unable to resolve: ${location}`);
            }
        }
        refs = refs.concat(getAnimReferencesFromNodes(refChecker, location, elem.children));
    }
    return refs;
}

// Handle category and meta tag references

function formQuery(ref:Ref):AnimQuery {
    let node = new AssetNode(ref.type, ref.att);

    let query:AnimQuery = {
        categories: node.categoryFilter.allOf,  // Until we optimize the advanced AnimDB category searching
        includeMeta: node.metaFilter.allOf,
        includeSomeMeta: node.metaFilter.someOf,
        excludeMeta: node.metaFilter.noneOf
    };

    return query;
}


/**
 * Hold one preflight error.
 * @class Error
 * @private
 */
class Error {
    constructor(public location:any, public message:string, public code:string) {
    }
    toString() {
        return `   ${this.code} ${this.message}`;
    }
}

export default AnimRefChecker;
