import fs = require('fs');
import path = require('path');
import rimraf = require('rimraf');
import * as hash from 'object-hash';
import cli from './cli';
import {EventEmitter} from 'events';
import glob = require('glob');
import { api } from 'jibo-anim-db';
const { KeyframesCompositer, keysObjToAnimObject } = require('jibo-keyframes');
import { PathUtils } from 'jibo-plugins';

/**
 * Statically compile a skill's keys files into anim files.
 * ```
 * import {KeysCompiler} from 'jibo-dev';
 * ```
 * @class KeysCompiler
 * @param {string} projectRoot Path to the skill's project-level directory.
 */

export class KeysCompiler extends EventEmitter {
    private skillDir: string;
    private animdb: string;
    private files: any;
    private skipUnderscores: boolean;

    /**
     * Command-line tool for compiling a skill's keys files into anim files.
     * @method KeysCompiler.cli
     * @private
     */
    static cli(): void {
        cli();
    }

    /**
     * Command-line tool entrypoint
     * @method KeysCompiler.exec
     * @param {any} args Options for controlling the compiler.
     * @return {EventEmitter} Emits 'lintError', 'end' and 'log' event
     */
    static exec(args): EventEmitter {
        const compiler = new KeysCompiler(args);
        compiler.run();
        return compiler;
    }

    constructor(public args:any) {
        super();
        this.skillDir = args.skill;
        this.files = Array.isArray(args.file) ? args.file : (args.file ? [args.file] : undefined);
        this.animdb = args.animdb;
        this.skipUnderscores = args['skip-underscores'];
    }

    /**
     * Main entry point for execution. This loads the keys files and compiles them.
     * @method KeysCompiler.run
     */
    public run():void {
        this.init().then(() => {
            if (!this.files) {
                this.removeOldFiles();
            }
            this.compileKeysFiles(()=>this.emit('end'));
        }).catch((err)=>{
            if (`${err}`.endsWith('node_modules/jibo-anim-db-animations/animdb.json')) {
                console.log('Skill has no animation database -- any animation references will cause the program to fail.');
            } else {
                console.log('Failed to initialize', err);
            }
            this.emit('end');
        });
    }

    // Load the optional animdb if provided, otherwise the skill's installed animation DB.

    private async init(): Promise<void> {
        const animDBpath = this.animdb || path.join(this.skillDir, 'node_modules/jibo-anim-db-animations/animdb.json');
        return api.init(null, animDBpath);
    }

    private removeOldFiles() {
        for (let ext of ['anim', 'assets']) {
            const keysPath = path.resolve(this.skillDir, 'animations/*' + `*/*.${ext}`);
            rimraf.sync(keysPath);
        }
    }

    private compileKeysFiles(cb) {
        //                             The "+" below is a hack -- v -- to keep JSDocs from complaining.
        let keysPath = path.resolve(this.skillDir, 'animations/*' + '*/*.keys');
        const files = this.files || glob.sync(keysPath);
        if (!files.length) {
            this.emit('log', `No keys found in ${this.skillDir}/animations`);
        }
        for (const filename of files) {
            if (this.skipUnderscores && filename.indexOf('/_') !== -1) {
                continue;
            }
            let compositer = new KeyframesCompositer(this.skillDir);
            compositer.setNoWarn();
            let animName = filename.replace('.keys', '.anim');
            if (fs.existsSync(animName)) {
                fs.unlinkSync(animName);
            }
            let keyframes = compositer.compositeKeysfile(filename);
            if (compositer.errors.length !== 0) {
                console.error(`FAILED: ${filename} ${compositer.errors.join(', ')}`);
                continue;
            }
            let anim = keysObjToAnimObject(keyframes, filename);
            fs.writeFileSync(animName, JSON.stringify(anim, null, 4), 'utf8');

            let assets = this.getAssetsFromKeys(keyframes, '', this.skillDir);
            fs.writeFileSync(animName.replace(/anim$/,'assets'), JSON.stringify(assets, null, 4), 'utf8');
        }

        cb();
    }

    private getAssetsFromKeys(data, assetPack, root): Array<any>
    {
        let assets:any = {};
        data.layers.forEach((layer:any) =>
        {
            layer.keyframes.forEach((keyframe:any) =>
            {
                let obj;
                const AudioEvent = keyframe.value.AudioEvent;
                const Pixi = keyframe.value.Pixi;
                const Texture = keyframe.value.Texture;
                if (AudioEvent)
                {
                    obj = {
                        id: AudioEvent.file,
                        type: 'sound',
                        src: AudioEvent.file
                    };
                }
                else if (Pixi)
                {
                    obj = {
                        id: Pixi,
                        type: 'timeline',
                        //upload: this.upload,
                        src: Pixi
                    };
                }
                else if (PathUtils.isImage(Texture))
                {
                    const src:string = Texture;
                    obj = {
                        id: src, // not Texture, we need the resolved file path.
                        type: 'texture',
                        src: src
                    };
                }
                if (obj) {
                    assets[obj.id] = obj;
                }
            });
        });
        const assetList:Array<any> = [];
        for (let assetId in assets) {
            assetList.push(assets[assetId]);
        }
        // Add animdb object hash metadata so that the .assets file changes in the case that its
        // containing .keys file only changes in its animdb field (which isn't otherwise picked up)
        assetList.push({
            type: 'metadata',
            animdb: data.animdb ? hash(data.animdb) : hash({})
        });
        return assetList;
    }

}

export default KeysCompiler;
