import JiboDev from '../JiboDev';
import rimraf = require('rimraf');

export default function(gulp, dev:JiboDev) {
    gulp.task('clean', function(done){

        let deletePromises = [];

        deletePromises.push(new Promise((resolve) => {
            rimraf(dev.config.map, {disableGlob: true}, ()=> {
                resolve();
            });
        }));
        deletePromises.push(new Promise((resolve) => {
            rimraf(dev.config.bundle, {disableGlob: true}, ()=> {
                resolve();
            });
        }));
        deletePromises.push(new Promise((resolve) => {
            rimraf(dev.config.rules, {disableGlob: true}, ()=> {
                resolve();
            });
        }));

        for (let extraFileToDelete of dev.config.clean) {
            deletePromises.push(new Promise((resolve) => {
                rimraf(extraFileToDelete, {disableGlob: true}, ()=> {
                    resolve();
                });
            }));
        }

        return Promise.all(deletePromises);
    });
}
